function MatchesView({
  matches,
  loading,
  onReload,
}: {
  matches: MatchRow[];
  loading: boolean;
  onReload: () => void;
}) {
  const [cancelOpen, setCancelOpen] = useState(false);
  const [signupsOpen, setSignupsOpen] = useState(false);
  const [editOpen, setEditOpen] = useState(false);
  const [selectedMatch, setSelectedMatch] = useState<MatchRow | null>(null);

  const handleCancelClick = (m: MatchRow) => {
    setSelectedMatch(m);
    setCancelOpen(true);
  };

  const handleSignupsClick = (m: MatchRow) => {
    setSelectedMatch(m);
    setSignupsOpen(true);
  };

  const handleEditClick = (m: MatchRow) => {
    setSelectedMatch(m);
    setEditOpen(true);
  };

  return (
    <div>
      <Toolbar
        title="Mecze"
        description="Zarządzanie terminami, opłatami, miejscami i anulacjami meczów."
        onReload={onReload}
        loading={loading}
      />

      <div className="overflow-hidden rounded-xl border border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
        <Table>
          <TableHeader>
            <TableRow className="border-zinc-200 hover:bg-transparent">
              <TableHead className="text-zinc-700">Data</TableHead>
              <TableHead className="text-zinc-700">Godzina</TableHead>
              <TableHead className="text-zinc-700">Lokalizacja</TableHead>
              <TableHead className="text-right text-zinc-700">Miejsca</TableHead>
              <TableHead className="text-right text-zinc-700">Rozegrane</TableHead>
              <TableHead className="text-right text-zinc-700">Opłata</TableHead>
              <TableHead className="text-right text-zinc-700">Akcje</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {matches.length === 0 ? (
              <TableRow>
                <TableCell colSpan={7} className="h-24 text-center text-sm text-zinc-500 dark:text-zinc-400">
                  Brak meczów w bazie.
                </TableCell>
              </TableRow>
            ) : (
              matches.map((m) => (
                <TableRow key={m.id} className="border-zinc-100">
                  <TableCell className="align-middle">{m.date}</TableCell>
                  <TableCell className="align-middle">{m.time}</TableCell>
                  <TableCell className="align-middle">{m.location}</TableCell>
                  <TableCell className="text-right align-middle tabular-nums">
                    {m.players_count}/{m.max_slots || "?"}
                  </TableCell>
                  <TableCell className="text-right align-middle tabular-nums">{m.played}</TableCell>
                  <TableCell className="text-right align-middle tabular-nums">
                    {m.fee_pln !== null ? `${m.fee_pln} zł` : "–"}
                  </TableCell>
                  <TableCell className="text-right align-middle">
                    <div className="flex flex-wrap justify-end gap-2">
                      {m.cancelled ? (
                        <Badge className="bg-red-600 text-white">Anulowany</Badge>
                      ) : (
                        <>
                          <Button size="sm" variant="outline" onClick={() => handleEditClick(m)}>
                            Edytuj
                          </Button>
                          <Button size="sm" variant="outline" onClick={() => handleSignupsClick(m)}>
                            Zapisy
                          </Button>
                          <Button size="sm" variant="outline" onClick={() => handleCancelClick(m)}>
                            Anuluj
                          </Button>
                        </>
                      )}
                    </div>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      <Dialog open={editOpen} onOpenChange={(o) => !o && setEditOpen(false)}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Edytuj mecz</DialogTitle>
          </DialogHeader>
          {selectedMatch && <MatchEditDialogContent match={selectedMatch} onEdited={() => { setEditOpen(false); onReload(); }} />}
        </DialogContent>
      </Dialog>

      <Dialog open={cancelOpen} onOpenChange={(o) => !o && setCancelOpen(false)}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Anulować mecz?</DialogTitle>
          </DialogHeader>
          {selectedMatch && <MatchCancelDialogContent match={selectedMatch} onCancelled={() => { setCancelOpen(false); onReload(); }} />}
        </DialogContent>
      </Dialog>

      <Dialog open={signupsOpen} onOpenChange={(o) => !o && setSignupsOpen(false)}>
        <DialogContent className="sm:max-w-3xl">
          {selectedMatch && <MatchSignupsDialogContent match={selectedMatch} onClose={() => setSignupsOpen(false)} onReload={onReload} />}
        </DialogContent>
      </Dialog>
    </div>
  );
}

function MatchCancelDialogContent({
  match,
  onCancelled,
}: {
  match: MatchRow;
  onCancelled: () => void;
}) {
  const [reason, setReason] = useState("weather");
  const [saving, setSaving] = useState(false);

  const reasons = [
    { value: "no-lineup", label: "Brak składu" },
    { value: "weather", label: "Pogoda" },
    { value: "field-unavailable", label: "Boisko niedostępne" },
    { value: "insufficient-players", label: "Niewystarczająca liczba zawodników" },
    { value: "admin-decision", label: "Decyzja administratora" },
  ];

  const handleCancel = async () => {
    setSaving(true);
    try {
      const res = await fetch(API.matchCancel(match.id), {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ reason }),
      });

      const data = (await res.json().catch(() => ({}))) as { error?: string };

      if (!res.ok) {
        toast.error(data.error ?? "Nie udało się anulować meczu");
        return;
      }

      toast.success("Mecz został anulowany");
      onCancelled();
    } catch {
      toast.error("Błąd podczas anulacji meczu");
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <div className="space-y-4 py-2">
        <p className="text-sm text-zinc-600 dark:text-zinc-400">
          Mecz <strong>{match.date}</strong> o <strong>{match.time}</strong>, <strong>{match.location}</strong> (id {match.id}).
        </p>
        <div>
          <Label htmlFor="cancel-reason">Wybierz powód anulacji</Label>
          <Select value={reason} onValueChange={setReason}>
            <SelectTrigger id="cancel-reason" className="mt-1 border-zinc-200">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {reasons.map((r) => (
                <SelectItem key={r.value} value={r.value}>
                  {r.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          <p className="mt-2 text-xs text-zinc-500 dark:text-zinc-400">
            Wszyscy zapisani gracze otrzymają powiadomienie o anulacji.
          </p>
        </div>
      </div>
      <DialogFooter className="gap-2 sm:gap-0">
        <Button variant="outline" disabled={saving}>
          Zamknij
        </Button>
        <Button variant="destructive" onClick={handleCancel} disabled={saving}>
          {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" aria-hidden /> : null}
          Anuluj mecz
        </Button>
      </DialogFooter>
    </>
  );
}

function MatchSignupsDialogContent({
  match,
  onClose,
  onReload,
}: {
  match: MatchRow;
  onClose: () => void;
  onReload: () => void;
}) {
  const [signups, setSignups] = useState<MatchSignupPaidRow[]>([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState<number | null>(null);
  const [addGuestOpen, setAddGuestOpen] = useState(false);
  const [guestFirstName, setGuestFirstName] = useState("");
  const [guestLastName, setGuestLastName] = useState("");
  const [guestAlias, setGuestAlias] = useState("");
  const [addingGuest, setAddingGuest] = useState(false);

  useEffect(() => {
    setLoading(true);
    void (async () => {
      try {
        const res = await fetch(API.matchSignups(match.id));
        if (!res.ok) throw new Error();
        const data = await res.json();
        setSignups(data.signups);
      } catch {
        toast.error("Nie udało się wczytać zapisów");
      } finally {
        setLoading(false);
      }
    })();
  }, [match]);

  const togglePaid = async (userId: number, currentPaid: number) => {
    setSaving(userId);
    try {
      const res = await fetch(API.matchSignups(match.id), {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ user_id: userId, paid: !currentPaid }),
      });
      if (!res.ok) throw new Error();
      setSignups((prev) =>
        prev.map((s) => (s.user_id === userId ? { ...s, paid: currentPaid ? 0 : 1 } : s))
      );
      toast.success("Zapisano");
    } catch {
      toast.error("Nie udało się zapisać");
    } finally {
      setSaving(null);
    }
  };

  const handleAddGuest = async () => {
    if (!guestFirstName.trim() || !guestLastName.trim() || !guestAlias.trim()) {
      toast.error("Uzupełnij wszystkie dane gościa");
      return;
    }

    setAddingGuest(true);
    try {
      const res = await fetch(API.matchAddGuest(match.id), {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          first_name: guestFirstName,
          last_name: guestLastName,
          player_alias: guestAlias,
        }),
      });

      const data = (await res.json().catch(() => ({}))) as { error?: string };

      if (!res.ok) {
        toast.error(data.error ?? "Nie udało się dodać gościa");
        return;
      }

      toast.success("Gościnny piłkarz został dodany");
      setGuestFirstName("");
      setGuestLastName("");
      setGuestAlias("");
      setAddGuestOpen(false);
      onReload();
    } finally {
      setAddingGuest(false);
    }
  };

  const handleRemoveGuest = async (userId: number) => {
    const ok = window.confirm("Czy na pewno chcesz usunąć tego gościnnego piłkarza?");
    if (!ok) return;

    setSaving(userId);
    try {
      const res = await fetch(API.matchRemoveGuest(match.id), {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ user_id: userId }),
      });

      const data = (await res.json().catch(() => ({}))) as { error?: string };

      if (!res.ok) {
        toast.error(data.error ?? "Nie udało się usunąć piłkarza");
        return;
      }

      toast.success("Piłkarz został usunięty");
      onReload();
    } finally {
      setSaving(null);
    }
  };

  return (
    <>
      <DialogHeader>
        <DialogTitle>Zapisy i opłaty — {match.date} {match.time}</DialogTitle>
        <DialogDescription>{match.location}</DialogDescription>
      </DialogHeader>
      {loading ? (
        <div className="flex items-center justify-center py-8">
          <Loader2 className="h-6 w-6 animate-spin" aria-hidden />
        </div>
      ) : (
        <div className="space-y-4">
          {signups.length === 0 ? (
            <p className="text-center text-sm text-zinc-500 dark:text-zinc-400 py-8">
              Brak zapisów na ten mecz.
            </p>
          ) : (
            <div className="space-y-2">
              {signups.map((s) => (
                <div key={s.user_id} className="flex items-center justify-between p-3 border rounded-lg">
                  <div className="flex items-center gap-3 flex-1">
                    <PlayerAvatar
                      photoPath={s.profile_photo_path}
                      firstName={s.first_name}
                      lastName={s.last_name}
                      size="sm"
                    />
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <p className="font-medium">{s.first_name} {s.last_name}</p>
                        {s.is_temporary ? (
                          <Badge className="bg-amber-100 text-amber-800">Gościnny</Badge>
                        ) : null}
                      </div>
                      <p className="text-sm text-zinc-500">{s.zawodnik}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    {!s.is_temporary && (
                      <Badge variant={s.commitment === 1 ? "default" : "secondary"}>
                        {s.commitment === 1 ? "Potwierdzony" : "Niepewny"}
                      </Badge>
                    )}
                    {!s.is_temporary && (
                      <Button
                        size="sm"
                        variant={s.paid ? "default" : "outline"}
                        onClick={() => togglePaid(s.user_id, s.paid)}
                        disabled={saving === s.user_id}
                      >
                        {saving === s.user_id ? <Loader2 className="h-4 w-4 animate-spin" /> : s.paid ? "Opłacony" : "Nieopłacony"}
                      </Button>
                    )}
                    {s.is_temporary && (
                      <Button
                        size="sm"
                        variant="destructive"
                        onClick={() => handleRemoveGuest(s.user_id)}
                        disabled={saving === s.user_id}
                      >
                        {saving === s.user_id ? <Loader2 className="h-4 w-4 animate-spin" /> : "Usuń"}
                      </Button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
      <DialogFooter className="gap-2 sm:gap-0">
        <Button variant="outline" size="sm" onClick={() => setAddGuestOpen(true)}>
          Dodaj gościa
        </Button>
        <Button variant="outline" onClick={onClose}>
          Zamknij
        </Button>
      </DialogFooter>

      <Dialog open={addGuestOpen} onOpenChange={setAddGuestOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Dodaj gościnnego piłkarza</DialogTitle>
            <DialogDescription>
              Piłkarz będzie dostępny tylko na ten mecz
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-3 py-2">
            <div>
              <Label htmlFor="guest-fn">Imię</Label>
              <Input
                id="guest-fn"
                className="mt-1 border-zinc-200"
                value={guestFirstName}
                onChange={(e) => setGuestFirstName(e.target.value)}
                disabled={addingGuest}
              />
            </div>
            <div>
              <Label htmlFor="guest-ln">Nazwisko</Label>
              <Input
                id="guest-ln"
                className="mt-1 border-zinc-200"
                value={guestLastName}
                onChange={(e) => setGuestLastName(e.target.value)}
                disabled={addingGuest}
              />
            </div>
            <div>
              <Label htmlFor="guest-alias">Pseudonim</Label>
              <Input
                id="guest-alias"
                className="mt-1 border-zinc-200"
                value={guestAlias}
                onChange={(e) => setGuestAlias(e.target.value)}
                disabled={addingGuest}
              />
            </div>
          </div>
          <DialogFooter className="gap-2 sm:gap-0">
            <Button
              variant="outline"
              onClick={() => setAddGuestOpen(false)}
              disabled={addingGuest}
            >
              Anuluj
            </Button>
            <Button onClick={handleAddGuest} disabled={addingGuest}>
              {addingGuest ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null}
              Dodaj
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

function StatsView({
  stats,
  loading,
  onReload,
}: {
  stats: StatRow[];
  loading: boolean;
  onReload: () => void;
}) {
  const [q, setQ] = useState("");

  const filtered = useMemo(() => {
    const s = q.trim().toLowerCase();
    if (!s) return stats;
    return stats.filter(
      (row) =>
        row.first_name.toLowerCase().includes(s) ||
        row.last_name.toLowerCase().includes(s) ||
        row.zawodnik.toLowerCase().includes(s)
    );
  }, [stats, q]);

  return (
    <div>
      <Toolbar
        title="Statystyki"
        description="Wpisy statystyk mecze — gole, asysty, dystans, interwencje."
        onReload={onReload}
        loading={loading}
      >
        <div className="relative w-full min-w-[200px] sm:w-64">
          <Search
            className="pointer-events-none absolute left-2.5 top-1/2 h-4 w-4 -translate-y-1/2 text-zinc-400"
            aria-hidden
          />
          <Input
            className="border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800 pl-9"
            placeholder="Szukaj…"
            value={q}
            onChange={(e) => setQ(e.target.value)}
            aria-label="Filtruj statystyki"
          />
        </div>
      </Toolbar>

      <div className="overflow-hidden rounded-xl border border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
        <Table>
          <TableHeader>
            <TableRow className="border-zinc-200 hover:bg-transparent">
              <TableHead className="w-12 text-zinc-700" />
              <TableHead className="text-zinc-700">Zawodnik</TableHead>
              <TableHead className="text-right text-zinc-700">Gole</TableHead>
              <TableHead className="text-right text-zinc-700">Asysty</TableHead>
              <TableHead className="text-right text-zinc-700">Dystans (m)</TableHead>
              <TableHead className="text-right text-zinc-700">Interwencje</TableHead>
              <TableHead className="text-right text-zinc-700">Mecz ID</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {filtered.length === 0 ? (
              <TableRow>
                <TableCell colSpan={7} className="h-24 text-center text-sm text-zinc-500 dark:text-zinc-400">
                  {stats.length === 0 ? "Brak statystyk w bazie." : "Brak wyników dla podanego filtra."}
                </TableCell>
              </TableRow>
            ) : (
              filtered.map((s) => (
                <TableRow key={s.id} className="border-zinc-100">
                  <TableCell className="align-middle">
                    <PlayerAvatar
                      photoPath={s.profile_photo_path}
                      firstName={s.first_name}
                      lastName={s.last_name}
                      size="sm"
                      ringClassName="ring-2 ring-zinc-200"
                    />
                  </TableCell>
                  <TableCell className="align-middle">
                    <PlayerNameStack
                      firstName={s.first_name}
                      lastName={s.last_name}
                      nick={s.zawodnik}
                    />
                  </TableCell>
                  <TableCell className="text-right align-middle tabular-nums">{s.goals}</TableCell>
                  <TableCell className="text-right align-middle tabular-nums">{s.assists}</TableCell>
                  <TableCell className="text-right align-middle tabular-nums">{s.distance}</TableCell>
                  <TableCell className="text-right align-middle tabular-nums">{s.saves}</TableCell>
                  <TableCell className="text-right align-middle tabular-nums">
                    <Link href={`/panel-admina?match=${s.match_id}`} className="text-emerald-600 hover:underline">
                      {s.match_id}
                    </Link>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>
    </div>
  );
}

export function AdminPanel() {
  const [tab, setTab] = useState<TabId>("dashboard");
  const [loading, setLoading] = useState(true);
  const [summary, setSummary] = useState<Summary | null>(null);
  const [appSettings, setAppSettings] = useState<AppSettings | null>(null);
  const [savingAppSettings, setSavingAppSettings] = useState(false);
  const [activity, setActivity] = useState<
    {
      text: string;
      time: string;
      actorName: string | null;
      actorLabel?: string;
      timeDisplay?: string;
    }[]
  >([]);
  const [users, setUsers] = useState<UserRow[]>([]);
  const [matches, setMatches] = useState<MatchRow[]>([]);
  const [stats, setStats] = useState<StatRow[]>([]);
  const [analytics, setAnalytics] = useState<AnalyticsPayload | null>(null);
  const [analyticsRange, setAnalyticsRange] = useState(() => defaultAnalyticsDateRange());
  /** Osobno od `loading`, żeby uniknąć wyścigów przy szybkiej zmianie zakładki podczas fetcha analityki. */
  const [analyticsLoading, setAnalyticsLoading] = useState(false);
  const [analyticsFetchNonce, setAnalyticsFetchNonce] = useState(0);
  const [analyticsHourly, setAnalyticsHourly] = useState<AnalyticsHourlyPayload | null>(null);
  const [logoutOpen, setLogoutOpen] = useState(false);

  const onAnalyticsFromChange = useCallback((v: string) => {
    setAnalyticsRange((prev) => {
      const from = v;
      const to = from > prev.to ? from : prev.to;
      return { from, to };
    });
  }, []);

  const onAnalyticsToChange = useCallback((v: string) => {
    setAnalyticsRange((prev) => {
      const to = v;
      const from = prev.from > to ? to : prev.from;
      return { from, to };
    });
  }, []);

  const loadDashboard = useCallback(async () => {
    setLoading(true);
    try {
      const [s, a, st] = await Promise.all([fetch(API.summary), fetch(API.activity), fetch(API.appSettings)]);
      if (!s.ok || !a.ok || !st.ok) throw new Error();
      setSummary(await s.json());
      setActivity(await a.json());
      setAppSettings(await st.json());
    } catch {
      toast.error("Nie udało się wczytać przeglądu");
    } finally {
      setLoading(false);
    }
  }, []);

  const saveAppSetting = useCallback(
    async (next: Partial<AppSettings>) => {
      setSavingAppSettings(true);
      try {
        const res = await fetch(API.appSettings, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(next),
        });
        const j = (await res.json().catch(() => ({}))) as AppSettings & { error?: string };
        if (!res.ok) {
          throw new Error(j.error ?? "Nie udało się zapisać ustawienia");
        }
        if (typeof j.match_notification_prompt_enabled === "boolean" && "home_youtube_url" in j) {
          setAppSettings({
            match_notification_prompt_enabled: j.match_notification_prompt_enabled,
            home_youtube_url: j.home_youtube_url ?? null,
          });
        } else {
          setAppSettings((prev) => (prev ? { ...prev, ...next } : (next as AppSettings)));
        }
        toast.success("Zapisano ustawienia");
      } catch (e) {
        toast.error(e instanceof Error ? e.message : "Nie udało się zapisać ustawienia");
        // odśwież z serwera, jeśli zapis nie wyszedł
        void fetch(API.appSettings)
          .then((r) => (r.ok ? (r.json() as Promise<AppSettings>) : null))
          .then((data) => data && setAppSettings(data))
          .catch(() => {});
      } finally {
        setSavingAppSettings(false);
      }
    },
    []
  );

  const loadUsers = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(API.users);
      if (!res.ok) throw new Error();
      setUsers(await res.json());
    } catch {
      toast.error("Nie udało się wczytać użytkowników");
    } finally {
      setLoading(false);
    }
  }, []);

  const loadMatches = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(API.matches);
      if (!res.ok) throw new Error();
      const rows = await res.json();
      setMatches(
        rows.map((m: MatchRow & { played?: number; fee_pln?: number | null }) => ({
          ...m,
          played: m.played ?? 0,
          fee_pln: m.fee_pln ?? null,
        }))
      );
    } catch {
      toast.error("Nie udało się wczytać meczów");
    } finally {
      setLoading(false);
    }
  }, []);

  const loadStats = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(API.stats);
      if (!res.ok) throw new Error();
      setStats(await res.json());
    } catch {
      toast.error("Nie udało się wczytać statystyk");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (tab === "dashboard") void loadDashboard();
    if (tab === "users") void loadUsers();
    if (tab === "matches") void loadMatches();
    if (tab === "stats") void loadStats();
    if (tab === "lineups" || tab === "wallets") setLoading(false);
  }, [tab, loadDashboard, loadUsers, loadMatches, loadStats]);

  useEffect(() => {
    if (tab !== "analytics") {
      setAnalyticsLoading(false);
      setAnalyticsHourly(null);
      return;
    }
    let cancelled = false;
    const { from, to } = analyticsRange;
    setAnalyticsLoading(true);
    void (async () => {
      try {
        const [resA, resH] = await Promise.all([
          fetch(API.analytics(from, to)),
          fetch(API.analyticsHourly),
        ]);
        if (cancelled) return;
        if (!resA.ok) throw new Error();
        setAnalytics(await resA.json());
        if (!resH.ok) {
          toast.error("Nie udało się wczytać wykresów godzinowych (ostatnie 7 dni)");
        } else {
          setAnalyticsHourly((await resH.json()) as AnalyticsHourlyPayload);
        }
      } catch {
        if (!cancelled) {
          toast.error("Nie udało się wczytać analityki");
          setAnalytics(null);
          setAnalyticsHourly(null);
        }
      } finally {
        if (!cancelled) setAnalyticsLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [tab, analyticsRange, analyticsFetchNonce]);

  return (
    <div className="min-h-screen bg-zinc-50 text-zinc-900 dark:bg-zinc-950 dark:text-zinc-100">
      <div className="flex min-h-screen flex-col lg:flex-row">
        <aside
          className={cn(
            "border-zinc-200/80 bg-gradient-to-br from-emerald-950 via-emerald-900 to-emerald-950 text-white",
            "lg:w-60 lg:shrink-0 lg:border-r"
          )}
        >
          <div className="flex flex-col gap-6 p-4 lg:sticky lg:top-0 lg:max-h-screen lg:overflow-y-auto">
            <div className="flex items-center gap-3 border-b border-white/10 pb-4">
              <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-white/10 text-lg shadow-inner">
                ⚽
              </div>
              <div>
                <p className="text-xs font-medium uppercase tracking-wider text-emerald-300/90">
                  Akademia
                </p>
                <p className="font-semibold leading-tight">Panel administratora</p>
              </div>
            </div>

            <nav className="flex flex-wrap gap-2 lg:flex-col lg:gap-1">
              {tabs.map((t) => {
                const Icon = t.icon;
                const active = tab === t.id;
                const pinBadge =
                  t.id === "users" &&
                  ((summary?.pin_reset_requests ?? 0) > 0 ||
                    users.some((u) => (u.pin_reset_requested ?? 0) === 1));
                return (
                  <button
                    key={t.id}
                    type="button"
                    onClick={() => setTab(t.id)}
                    className={cn(
                      "flex items-center gap-2 rounded-lg px-3 py-2.5 text-left text-sm font-medium transition-colors",
                      active
                        ? "bg-white/15 text-white shadow-sm"
                        : "text-emerald-100/80 hover:bg-white/10 hover:text-white"
                    )}
                  >
                    <Icon className="h-4 w-4 shrink-0 opacity-90" aria-hidden />
                    <span className="flex min-w-0 flex-1 items-center justify-between gap-2">
                      {t.label}
                      {pinBadge ? (
                        <span
                          className="inline-flex min-h-[1.25rem] min-w-[1.25rem] shrink-0 items-center justify-center rounded-full bg-red-500 px-1.5 text-[10px] font-bold text-white"
                          title="Zgłoszenia zmiany PIN-u"
                          aria-label="Zgłoszenia zmiany PIN-u"
                        />
                      ) : null}
                    </span>
                  </button>
                );
              })}
            </nav>

            <div className="mt-auto flex flex-col gap-2 border-t border-white/10 pt-4">
              <Link
                href="/terminarz"
                className="flex items-center gap-2 rounded-lg px-3 py-2 text-sm text-emerald-100/90 transition-colors hover:bg-white/10 hover:text-white"
              >
                <Calendar className="h-4 w-4" aria-hidden />
                Terminarz (edycja)
              </Link>
              <Link
                href="/"
                className="flex items-center gap-2 rounded-lg px-3 py-2 text-sm text-emerald-100/90 transition-colors hover:bg-white/10 hover:text-white"
              >
                <ArrowLeft className="h-4 w-4" aria-hidden />
                Strona główna
              </Link>
              <button
                type="button"
                onClick={() => setLogoutOpen(true)}
                className="flex items-center gap-2 rounded-lg px-3 py-2 text-sm text-emerald-100/90 transition-colors hover:bg-white/10 hover:text-white"
              >
                <LogOut className="h-4 w-4" aria-hidden />
                Wyloguj
              </button>
            </div>
          </div>
        </aside>

        <main className="relative flex-1 overflow-x-hidden p-4 sm:p-6 lg:p-8">
          {(tab === "lineups" || tab === "wallets"
            ? false
            : tab === "analytics"
              ? analyticsLoading
              : loading) && (
            <div
              className="pointer-events-none absolute right-6 top-6 flex items-center gap-2 text-sm text-zinc-500 dark:text-zinc-400"
              aria-live="polite"
            >
              <Loader2 className="h-4 w-4 animate-spin" aria-hidden />
              Wczytywanie…
            </div>
          )}

          <div className="mx-auto max-w-6xl">
            {tab === "dashboard" && (
              <DashboardView
                summary={summary}
                appSettings={appSettings}
                savingAppSettings={savingAppSettings}
                onToggleMatchNotificationPrompt={(enabled) =>
                  void saveAppSetting({ match_notification_prompt_enabled: enabled })
                }
                onSaveHomeYoutubeUrl={(url) => void saveAppSetting({ home_youtube_url: url })}
                activity={activity}
                loading={loading}
                onReload={loadDashboard}
                onGoToTab={setTab}
              />
            )}
            {tab === "users" && <UsersView users={users} loading={loading} onReload={loadUsers} />}
            {tab === "wallets" && <AdminWalletsSaldoSection />}
            {tab === "matches" && <MatchesView matches={matches} loading={loading} onReload={loadMatches} />}
            {tab === "lineups" && <MatchLineupAdmin />}
            {tab === "analytics" && (
              <AnalyticsView
                data={analytics}
                hourlyData={analyticsHourly}
                loading={analyticsLoading}
                dateFrom={analyticsRange.from}
                dateTo={analyticsRange.to}
                onDateFromChange={onAnalyticsFromChange}
                onDateToChange={onAnalyticsToChange}
                onReload={() => setAnalyticsFetchNonce((n) => n + 1)}
                onPresetRange={(from, to) => setAnalyticsRange({ from, to })}
              />
            )}
            {tab === "stats" && <StatsView stats={stats} loading={loading} onReload={loadStats} />}
          </div>
        </main>
      </div>

      <Dialog open={logoutOpen} onOpenChange={setLogoutOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Wylogować się?</DialogTitle>
            <DialogDescription>Czy na pewno chcesz zakończyć sesję?</DialogDescription>
          </DialogHeader>
          <DialogFooter className="gap-2 sm:gap-0">
            <Button variant="outline" onClick={() => setLogoutOpen(false)}>
              Nie
            </Button>
            <Button variant="destructive" asChild>
              <a href="/api/auth/logout">Tak</a>
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function Toolbar({
  title,
  description,
  onReload,
  loading,
  children,
}: {
  title: string;
  description?: string;
  onReload: () => void;
  loading: boolean;
  children?: React.ReactNode;
}) {
  return (
    <div className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
      <div>
        <h1 className="text-2xl font-bold tracking-tight text-zinc-900">{title}</h1>
        {description ? <p className="mt-1 text-sm text-zinc-600 dark:text-zinc-400">{description}</p> : null}
      </div>
      <div className="flex flex-wrap items-center gap-2">
        {children}
        <Button type="button" variant="outline" size="sm" onClick={onReload} disabled={loading}>
          <RefreshCw className={cn("mr-2 h-4 w-4", loading && "animate-spin")} aria-hidden />
          Odśwież
        </Button>
      </div>
    </div>
  );
}

type AnalyticsScreenSortKey = "label" | "views" | "unique";

function downloadAnalyticsScreensCsv(
  rows: AnalyticsPayload["screens"],
  range: { from: string; to: string }
) {
  const esc = (s: string) => `"${s.replace(/"/g, '""')}"`;
  const header = ["Ekran", "Klucz ekranu", "Odsłony", "Unikalni odbiorcy"];
  const body = rows.map((r) =>
    [esc(r.label), r.screen_key, String(r.total_views), String(r.unique_visitors)].join(";")
  );
  const csv = "\uFEFF" + [header.join(";"), ...body].join("\r\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `analityka-ekrany-${range.from}_${range.to}.csv`;
  a.rel = "noopener";
  a.click();
  URL.revokeObjectURL(url);
}

function AnalyticsView({
  data,
  hourlyData,
  loading,
  dateFrom,
  dateTo,
  onDateFromChange,
  onDateToChange,
  onReload,
  onPresetRange,
}: {
  data: AnalyticsPayload | null;
  hourlyData: AnalyticsHourlyPayload | null;
  loading: boolean;
  dateFrom: string;
  dateTo: string;
  onDateFromChange: (v: string) => void;
  onDateToChange: (v: string) => void;
  onReload: () => void;
  onPresetRange: (from: string, to: string) => void;
}) {
  const [screenQuery, setScreenQuery] = useState("");
  const [activityQuery, setActivityQuery] = useState("");
  const [sortKey, setSortKey] = useState<AnalyticsScreenSortKey>("views");
  const [sortDir, setSortDir] = useState<"asc" | "desc">("desc");
  const maxDate = todayYmd();

  const toggleSort = useCallback((key: AnalyticsScreenSortKey) => {
    setSortKey((prev) => {
      if (prev === key) {
        setSortDir((d) => (d === "asc" ? "desc" : "asc"));
        return prev;
      }
      setSortDir(key === "label" ? "asc" : "desc");
      return key;
    });
  }, []);

  const viewSplit =
    data != null && data.totals.anonymous_views + data.totals.authenticated_views > 0
      ? {
          anonPct:
            Math.round(
              (data.totals.anonymous_views /
                (data.totals.anonymous_views + data.totals.authenticated_views)) *
                1000
            ) / 10,
          authPct:
            Math.round(
              (data.totals.authenticated_views /
                (data.totals.anonymous_views + data.totals.authenticated_views)) *
                1000
            ) / 10,
        }
      : null;

  const screensPrepared = useMemo(() => {
    if (!data) return [];
    const q = screenQuery.trim().toLowerCase();
    const filtered = !q
      ? data.screens
      : data.screens.filter(
          (r) =>
            r.label.toLowerCase().includes(q) ||
            r.screen_key.toLowerCase().includes(q)
        );
    const mult = sortDir === "asc" ? 1 : -1;
    return [...filtered].sort((a, b) => {
      if (sortKey === "label") return mult * a.label.localeCompare(b.label, "pl");
      if (sortKey === "unique") return mult * (a.unique_visitors - b.unique_visitors);
      return mult * (a.total_views - b.total_views);
    });
  }, [data, screenQuery, sortKey, sortDir]);

  const eventsPrepared = useMemo(() => {
    const ev = data?.activity_events ?? [];
    const q = activityQuery.trim().toLowerCase();
    if (!q) return ev;
    return ev.filter(
      (e) =>
        e.actor_label.toLowerCase().includes(q) ||
        e.action.toLowerCase().includes(q) ||
        e.time_display.toLowerCase().includes(q)
    );
  }, [data, activityQuery]);

  const rangeSummary =
    data != null
      ? `${new Date(`${data.range.from}T12:00:00`).toLocaleDateString("pl-PL")} – ${new Date(`${data.range.to}T12:00:00`).toLocaleDateString("pl-PL")}`
      : null;

  return (
    <div aria-busy={loading}>
      <Toolbar
        title="Analityka wejść"
        description="Dane zbierane przy otwarciu stron przez użytkowników (bez panelu admina). Zakres dat to dni kalendarzowe w strefie Polski (Europe/Warsaw). Zmiana dat wczytuje raport ponownie."
        onReload={onReload}
        loading={loading}
      >
        <div className="flex w-full flex-col gap-3 xl:w-auto">
          <div className="flex flex-wrap items-end gap-2">
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800"
              disabled={loading}
              onClick={() => {
                const r = analyticsPresetLastNDaysInclusive(7);
                onPresetRange(r.from, r.to);
              }}
            >
              7 dni
            </Button>
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800"
              disabled={loading}
              onClick={() => {
                const r = analyticsPresetLastNDaysInclusive(30);
                onPresetRange(r.from, r.to);
              }}
            >
              30 dni
            </Button>
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800"
              disabled={loading}
              onClick={() => {
                const r = analyticsPresetMonthToDate();
                onPresetRange(r.from, r.to);
              }}
            >
              Ten miesiąc
            </Button>
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800"
              disabled={loading}
              onClick={() => {
                const r = defaultAnalyticsDateRange();
                onPresetRange(r.from, r.to);
              }}
            >
              Wczoraj–dziś
            </Button>
          </div>
          <div className="flex flex-wrap items-end gap-3">
            <div>
              <Label htmlFor="adm-an-from" className="text-xs text-zinc-600 dark:text-zinc-400">
                Od
              </Label>
              <Input
                id="adm-an-from"
                type="date"
                max={maxDate}
                className="mt-1 w-[11rem] border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800"
                value={dateFrom}
                onChange={(e) => onDateFromChange(e.target.value)}
              />
            </div>
            <div>
              <Label htmlFor="adm-an-to" className="text-xs text-zinc-600 dark:text-zinc-400">
                Do
              </Label>
              <Input
                id="adm-an-to"
                type="date"
                max={maxDate}
                className="mt-1 w-[11rem] border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800"
                value={dateTo}
                onChange={(e) => onDateToChange(e.target.value)}
              />
            </div>
          </div>
        </div>
      </Toolbar>

      <AdminAnalyticsHourlyCharts data={hourlyData} loading={loading && hourlyData === null} />

      {rangeSummary && data ? (
        <p className="mb-4 text-sm text-zinc-600 dark:text-zinc-400">
          <span className="font-medium text-zinc-800">Zakres raportu (dni kalendarzowe, PL):</span>{" "}
          {rangeSummary}{" "}
          <span className="text-zinc-500 dark:text-zinc-400">
            ({data.range.from} — {data.range.to})
          </span>
        </p>
      ) : null}

      <Card className="mb-6 border-amber-200/80 bg-amber-50/50 shadow-sm">
        <CardHeader className="pb-2">
          <CardTitle className="text-base text-amber-950">Jak czytać te liczby</CardTitle>
        </CardHeader>
        <CardContent className="space-y-2 text-sm text-amber-950/90">
          <p>
            <strong>Gracze zalogowani vs bez aktywności</strong> — spośród kont z rolą gracza (bez
            administratorów), ilu miało co najmniej jedno odsłonięcie strony zalogowane w wybranym
            okresie. Reszta to konta bez takich wejść w tym zakresie dat (nie znaczy to, że nigdy nie
            wchodzili).
          </p>
          <p>
            <strong>Rejestracje (samodzielne)</strong> — wpisy z dziennika aktywności przy
            rejestracji z formularza (nie obejmuje kont utworzonych przez administratora).
          </p>
          <p>
            <strong>Terminarz → zapis na mecz</strong> — gracze, którzy w okresie oglądali ekran
            terminarza zalogowani, a w tym samym okresie zapisali się na dowolny mecz (wg daty
            zapisu).
          </p>
          <p>
            <strong>Wejścia anonimowe vs zalogowane</strong> — udział surowych odsłon stron bez
            sesji vs z aktywną sesją (jedna osoba może generować wiele odsłon).
          </p>
          <p>
            <strong>Dziennik akcji</strong> — konkretne czynności zapisane po stronie serwera (nie
            mylić z samym otwarciem stron). Dla każdego wpisu widać kto (imię, nazwisko, pseudonim),
            opis akcji oraz znacznik czasu w Europe/Warsaw.
          </p>
        </CardContent>
      </Card>

      {!data && !loading ? (
        <p className="text-sm text-zinc-600 dark:text-zinc-400">Brak danych do wyświetlenia.</p>
      ) : null}

      {data ? (
        <>
          <Card className="mb-6 border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
            <CardHeader className="space-y-4">
              <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
                <div>
                  <CardTitle className="flex items-center gap-2 text-lg">
                    <ClipboardList className="h-5 w-5 text-emerald-700" aria-hidden />
                    Dziennik akcji użytkowników
                  </CardTitle>
                  <CardDescription className="mt-1">
                    Zdarzenia z serwera w wybranym zakresie dat (np. logowanie, zapisy na mecze, edycje
                    profilu). Najnowsze na górze. Do 400 wpisów na jedno wczytanie.
                  </CardDescription>
                </div>
              </div>
              <div className="relative w-full min-w-[200px] sm:max-w-md">
                <Search
                  className="pointer-events-none absolute left-2.5 top-1/2 h-4 w-4 -translate-y-1/2 text-zinc-400"
                  aria-hidden
                />
                <Input
                  className="border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800 pl-9"
                  placeholder="Szukaj po osobie, treści akcji lub czasie…"
                  value={activityQuery}
                  onChange={(e) => setActivityQuery(e.target.value)}
                  aria-label="Filtruj dziennik akcji"
                />
              </div>
            </CardHeader>
            <CardContent className="overflow-x-auto">
              <div className="max-h-[min(28rem,70vh)] overflow-y-auto overflow-x-auto rounded-xl border border-zinc-200/80">
                <Table>
                  <TableHeader>
                    <TableRow className="border-zinc-200 hover:bg-transparent">
                      <TableHead className="whitespace-nowrap text-zinc-700">Czas (PL)</TableHead>
                      <TableHead className="min-w-[10rem] text-zinc-700">Kto</TableHead>
                      <TableHead className="text-zinc-700">Czynność</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {(data.activity_events?.length ?? 0) === 0 ? (
                      <TableRow>
                        <TableCell
                          colSpan={3}
                          className="text-center text-sm text-zinc-500 dark:text-zinc-400"
                        >
                          Brak wpisów dziennika dla tego zakresu dat.
                        </TableCell>
                      </TableRow>
                    ) : eventsPrepared.length === 0 ? (
                      <TableRow>
                        <TableCell
                          colSpan={3}
                          className="text-center text-sm text-zinc-500 dark:text-zinc-400"
                        >
                          Brak wyników dla podanego filtra.
                        </TableCell>
                      </TableRow>
                    ) : (
                      eventsPrepared.map((row) => (
                        <TableRow key={row.id} className="border-zinc-100">
                          <TableCell className="whitespace-nowrap align-top text-xs tabular-nums text-zinc-600 dark:text-zinc-400">
                            <time dateTime={row.timestamp} title={row.timestamp}>
                              {row.time_display}
                            </time>
                          </TableCell>
                          <TableCell className="align-top text-sm font-medium text-zinc-900">
                            {row.actor_label}
                          </TableCell>
                          <TableCell className="align-top text-sm text-zinc-700 dark:text-zinc-300">
                            {row.action}
                          </TableCell>
                        </TableRow>
                      ))
                    )}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>

          <div className="mb-6 grid gap-4 sm:grid-cols-2 xl:grid-cols-4">
            <Card className="border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-zinc-800">Wszystkie odsłony</CardTitle>
              </CardHeader>
              <CardContent>
                <p className="text-2xl font-bold tabular-nums text-emerald-950 dark:text-emerald-100">
                  {data.totals.total_views}
                </p>
                <p className="mt-1 text-xs text-zinc-500 dark:text-zinc-400">
                  Unikalni odbiorcy (gość lub id gracza): {data.totals.unique_visitors}
                </p>
              </CardContent>
            </Card>
            <Card className="border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-zinc-800">
                  Odsłony: anonim / zalogowany
                </CardTitle>
              </CardHeader>
              <CardContent>
                {viewSplit ? (
                  <>
                    <p className="text-sm text-zinc-700">
                      Anonimowe: <strong>{data.totals.anonymous_views}</strong> (
                      {viewSplit.anonPct}%)
                    </p>
                    <p className="text-sm text-zinc-700">
                      Zalogowane: <strong>{data.totals.authenticated_views}</strong> (
                      {viewSplit.authPct}%)
                    </p>
                  </>
                ) : (
                  <p className="text-sm text-zinc-500 dark:text-zinc-400">Brak odsłon w okresie.</p>
                )}
              </CardContent>
            </Card>
            <Card className="border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-zinc-800">Gracze w bazie</CardTitle>
                <CardDescription className="text-xs">Konta nie-admin</CardDescription>
              </CardHeader>
              <CardContent className="space-y-1 text-sm">
                <p>
                  Z aktywnością w okresie:{" "}
                  <strong className="tabular-nums">{data.players.visited_in_range}</strong>
                  {data.players.pct_visited != null ? (
                    <span className="text-zinc-600 dark:text-zinc-400"> ({data.players.pct_visited}%)</span>
                  ) : null}
                </p>
                <p>
                  Bez wejść zalogowanych w okresie:{" "}
                  <strong className="tabular-nums">{data.players.not_visited_in_range}</strong>
                  {data.players.pct_not_visited != null ? (
                    <span className="text-zinc-600 dark:text-zinc-400"> ({data.players.pct_not_visited}%)</span>
                  ) : null}
                </p>
                <p className="text-xs text-zinc-500 dark:text-zinc-400">
                  Nowe konta (rejestracja): {data.players.self_service_registrations_in_range}
                </p>
              </CardContent>
            </Card>
            <Card className="border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
              <CardHeader className="pb-2">
                <CardTitle className="text-sm font-medium text-zinc-800">Terminarz → mecz</CardTitle>
                <CardDescription className="text-xs">Gracze (nie-admin)</CardDescription>
              </CardHeader>
              <CardContent className="space-y-1 text-sm">
                <p>
                  Oglądali terminarz:{" "}
                  <strong className="tabular-nums">
                    {data.terminarz_funnel.distinct_players_viewed}
                  </strong>
                </p>
                <p>
                  Zapis na mecz w okresie:{" "}
                  <strong className="tabular-nums">
                    {data.terminarz_funnel.distinct_players_viewed_and_signed_match_in_range}
                  </strong>
                  {data.terminarz_funnel.pct_signed_after_view != null ? (
                    <span className="text-zinc-600 dark:text-zinc-400">
                      {" "}
                      ({data.terminarz_funnel.pct_signed_after_view}%)
                    </span>
                  ) : data.terminarz_funnel.distinct_players_viewed === 0 ? (
                    <span className="text-zinc-500 dark:text-zinc-400"> (–)</span>
                  ) : null}
                </p>
              </CardContent>
            </Card>
          </div>

          <Card className="border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
            <CardHeader className="space-y-4">
              <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
                <div>
                  <CardTitle className="text-lg">Wejścia wg ekranu</CardTitle>
                  <CardDescription className="mt-1">
                    Liczba odsłon i szacunek unikalnych odbiorców (gość lub zalogowany gracz) w wybranym
                    zakresie. Kliknij nagłówek kolumny, aby sortować.
                  </CardDescription>
                </div>
                <div className="flex flex-wrap items-center gap-2">
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    className="border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800"
                    disabled={loading || screensPrepared.length === 0}
                    onClick={() => downloadAnalyticsScreensCsv(screensPrepared, data.range)}
                  >
                    <Download className="mr-2 h-4 w-4" aria-hidden />
                    CSV (widok)
                  </Button>
                </div>
              </div>
              <div className="relative w-full min-w-[200px] sm:max-w-xs">
                <Search
                  className="pointer-events-none absolute left-2.5 top-1/2 h-4 w-4 -translate-y-1/2 text-zinc-400"
                  aria-hidden
                />
                <Input
                  className="border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800 pl-9"
                  placeholder="Filtruj ekran lub klucz…"
                  value={screenQuery}
                  onChange={(e) => setScreenQuery(e.target.value)}
                  aria-label="Filtruj listę ekranów"
                />
              </div>
            </CardHeader>
            <CardContent className="overflow-x-auto">
              <div className="overflow-hidden rounded-xl border border-zinc-200/80">
                <Table>
                  <TableHeader>
                    <TableRow className="border-zinc-200 hover:bg-transparent">
                      <TableHead className="text-zinc-700">
                        <button
                          type="button"
                          className="inline-flex items-center gap-1.5 font-medium text-zinc-800 hover:text-emerald-900 dark:text-zinc-200 dark:hover:text-emerald-300"
                          onClick={() => toggleSort("label")}
                        >
                          Ekran
                          {sortKey === "label" ? (
                            sortDir === "asc" ? (
                              <ArrowUpAZ className="h-3.5 w-3.5 opacity-70" aria-hidden />
                            ) : (
                              <ArrowDownAZ className="h-3.5 w-3.5 opacity-70" aria-hidden />
                            )
                          ) : null}
                        </button>
                      </TableHead>
                      <TableHead className="text-right text-zinc-700">
                        <button
                          type="button"
                          className="inline-flex w-full items-center justify-end gap-1.5 font-medium text-zinc-800 hover:text-emerald-900 dark:text-zinc-200 dark:hover:text-emerald-300"
                          onClick={() => toggleSort("views")}
                        >
                          Odsłony
                          {sortKey === "views" ? (
                            sortDir === "asc" ? (
                              <ArrowUpAZ className="h-3.5 w-3.5 opacity-70" aria-hidden />
                            ) : (
                              <ArrowDownAZ className="h-3.5 w-3.5 opacity-70" aria-hidden />
                            )
                          ) : null}
                        </button>
                      </TableHead>
                      <TableHead className="text-right text-zinc-700">
                        <button
                          type="button"
                          className="inline-flex w-full items-center justify-end gap-1.5 font-medium text-zinc-800 hover:text-emerald-900 dark:text-zinc-200 dark:hover:text-emerald-300"
                          onClick={() => toggleSort("unique")}
                        >
                          Unikalni
                          {sortKey === "unique" ? (
                            sortDir === "asc" ? (
                              <ArrowUpAZ className="h-3.5 w-3.5 opacity-70" aria-hidden />
                            ) : (
                              <ArrowDownAZ className="h-3.5 w-3.5 opacity-70" aria-hidden />
                            )
                          ) : null}
                        </button>
                      </TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {data.screens.length === 0 ? (
                      <TableRow>
                        <TableCell colSpan={3} className="text-center text-sm text-zinc-500 dark:text-zinc-400">
                          Brak zapisanych wejść w tym okresie (dane pojawią się po pierwszych wizytach).
                        </TableCell>
                      </TableRow>
                    ) : screensPrepared.length === 0 ? (
                      <TableRow>
                        <TableCell colSpan={3} className="text-center text-sm text-zinc-500 dark:text-zinc-400">
                          Brak wyników dla podanego filtra.
                        </TableCell>
                      </TableRow>
                    ) : (
                      screensPrepared.map((row) => (
                        <TableRow key={row.screen_key} className="border-zinc-100">
                          <TableCell>
                            <span className="font-medium text-zinc-900">{row.label}</span>
                            <span className="ml-2 font-mono text-xs text-zinc-400">{row.screen_key}</span>
                          </TableCell>
                          <TableCell className="text-right tabular-nums">{row.total_views}</TableCell>
                          <TableCell className="text-right tabular-nums">{row.unique_visitors}</TableCell>
                        </TableRow>
                      ))
                    )}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>
        </>
      ) : null}
    </div>
  );
}

function DashboardView({
  summary,
  appSettings,
  savingAppSettings,
  onToggleMatchNotificationPrompt,
  onSaveHomeYoutubeUrl,
  activity,
  loading,
  onReload,
  onGoToTab,
}: {
  summary: Summary | null;
  appSettings: AppSettings | null;
  savingAppSettings: boolean;
  onToggleMatchNotificationPrompt: (enabled: boolean) => void;
  onSaveHomeYoutubeUrl: (url: string) => void;
  activity: {
    text: string;
    time: string;
    actorName: string | null;
    actorLabel?: string;
    timeDisplay?: string;
  }[];
  loading: boolean;
  onReload: () => void;
  onGoToTab: (t: TabId) => void;
}) {
  const [youtubeDraft, setYoutubeDraft] = useState("");

  useEffect(() => {
    if (appSettings) {
      setYoutubeDraft(appSettings.home_youtube_url ?? "");
    }
  }, [appSettings]);

  const metrics = [
    {
      key: "players",
      label: "Zarejestrowani",
      value: summary?.players,
      hint: "wszyscy użytkownicy",
      tab: "users" as const,
      icon: Users,
    },
    {
      key: "admins",
      label: "Administratorzy",
      value: summary?.admins,
      hint: "konta z uprawnieniami",
      tab: "users" as const,
      icon: Shield,
    },
    {
      key: "matches",
      label: "Mecze w bazie",
      value: summary?.matches,
      hint: "łącznie terminów",
      tab: "matches" as const,
      icon: Calendar,
    },
    {
      key: "upcoming",
      label: "Nadchodzące",
      value: summary?.upcoming_matches,
      hint: "nie rozegrane, od dziś",
      tab: "matches" as const,
      icon: Activity,
    },
    {
      key: "stats",
      label: "Wpisy statystyk",
      value: summary?.stats,
      hint: "wiersze w tabeli",
      tab: "stats" as const,
      icon: Table2,
    },
  ];

  return (
    <div>
      <Toolbar
        title="Przegląd"
        description="Skrót organizacji — kliknij kafelek, aby przejść do szczegółów."
        onReload={onReload}
        loading={loading}
      />

      {(summary?.pin_reset_requests ?? 0) > 0 ? (
        <div className="mb-6 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-950 shadow-sm">
          <p className="font-semibold">Zgłoszenia zmiany PIN-u</p>
          <p className="mt-1 text-red-900/90">
            Oczekujące sprawy (nowy PIN lub prośba o reset):{" "}
            <strong className="tabular-nums">{summary?.pin_reset_requests}</strong>. W zakładce{" "}
            <strong>Użytkownicy</strong> możesz <strong>zatwierdzić</strong> nowy PIN,{" "}
            <strong>odrzucić</strong> propozycję (pozostaje stary PIN) albo wykonać pełny{" "}
            <strong>restart PIN</strong> konta.
          </p>
        </div>
      ) : null}

      <div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-3">
        {metrics.map((m) => {
          const Icon = m.icon;
          return (
            <button
              key={m.key}
              type="button"
              onClick={() => onGoToTab(m.tab)}
              className="group text-left transition-transform hover:scale-[1.01] focus:outline-none focus-visible:ring-2 focus-visible:ring-emerald-500 focus-visible:ring-offset-2"
            >
              <Card className="h-full border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30 transition-shadow group-hover:shadow-md">
                <CardHeader className="flex flex-row items-start justify-between space-y-0 pb-2">
                  <div>
                    <CardTitle className="text-base font-semibold text-zinc-800">{m.label}</CardTitle>
                    <CardDescription className="text-xs">{m.hint}</CardDescription>
                  </div>
                  <div className="rounded-lg bg-emerald-50 p-2 text-emerald-700">
                    <Icon className="h-5 w-5" aria-hidden />
                  </div>
                </CardHeader>
                <CardContent>
                  <p className="text-3xl font-bold tabular-nums tracking-tight text-emerald-950 dark:text-emerald-100">
                    {m.value ?? "–"}
                  </p>
                </CardContent>
              </Card>
            </button>
          );
        })}
      </div>

      <Card className="mt-8 border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
        <CardHeader>
          <CardTitle className="text-lg">Ustawienia aplikacji</CardTitle>
          <CardDescription>Funkcje sterowane przez administratora.</CardDescription>
        </CardHeader>
        <CardContent>
          <label className="flex flex-wrap items-start justify-between gap-4 rounded-xl border border-zinc-200 bg-zinc-50/60 px-4 py-3">
            <span className="min-w-0">
              <span className="block text-sm font-semibold text-zinc-900">
                Pop-up: powiadomienia o meczach
              </span>
              <span className="mt-1 block text-sm text-zinc-600 dark:text-zinc-400">
                Włącza/wyłącza okno z adresem e-mail i zgodą do powiadomień o nowych terminach w terminarzu.
              </span>
            </span>
            <span className="flex items-center gap-2">
              <input
                type="checkbox"
                className="mt-0.5 h-4 w-4 rounded border-zinc-300 text-emerald-700 focus:ring-emerald-600"
                checked={Boolean(appSettings?.match_notification_prompt_enabled)}
                disabled={loading || savingAppSettings || appSettings == null}
                onChange={(e) => onToggleMatchNotificationPrompt(e.target.checked)}
                aria-label="Pop-up powiadomień o meczach"
              />
              <span className="text-sm font-medium text-zinc-700">
                {appSettings?.match_notification_prompt_enabled ? "Włączony" : "Wyłączony"}
              </span>
            </span>
          </label>

          <div className="mt-6 rounded-xl border border-zinc-200 bg-zinc-50/60 px-4 py-3">
            <div className="mb-2 flex items-start gap-2">
              <MonitorPlay
                className="mt-0.5 h-4 w-4 shrink-0 text-red-600"
                strokeWidth={2.25}
                aria-hidden
              />
              <div className="min-w-0">
                <p className="text-sm font-semibold text-zinc-900">Transmisja na stronie głównej (YouTube)</p>
                <p className="mt-1 text-sm text-zinc-600 dark:text-zinc-400">
                  Wklej pełny link do filmu lub transmisji na żywo (albo same 11 znaków ID). Wyczyść pole i zapisz, aby
                  usunąć — wtedy, jeśli masz ustawione zmienne środowiskowe, zadziałają one jako zapas.
                </p>
              </div>
            </div>
            <div className="flex flex-col gap-2 sm:flex-row sm:items-center">
              <Input
                type="url"
                placeholder="https://www.youtube.com/watch?v=…"
                value={youtubeDraft}
                onChange={(e) => setYoutubeDraft(e.target.value)}
                disabled={loading || appSettings == null}
                className="font-mono text-sm"
                autoComplete="off"
                spellCheck={false}
                aria-label="Adres YouTube na stronę główną"
              />
              <div className="flex shrink-0 gap-2">
                <Button
                  type="button"
                  disabled={loading || savingAppSettings || appSettings == null}
                  onClick={() => onSaveHomeYoutubeUrl(youtubeDraft.trim())}
                >
                  Zapisz transmisję
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  disabled={loading || savingAppSettings || appSettings == null || !youtubeDraft.trim()}
                  onClick={() => {
                    setYoutubeDraft("");
                    onSaveHomeYoutubeUrl("");
                  }}
                >
                  Wyczyść
                </Button>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      <Card className="mt-8 border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
        <CardHeader>
          <CardTitle className="text-lg">Ostatnia aktywność</CardTitle>
          <CardDescription>
            Do 25 ostatnich wpisów z serwera: kto (imię, nazwisko i pseudonim), co zrobił, kiedy — strefa
            Europe/Warsaw
          </CardDescription>
        </CardHeader>
        <CardContent>
          {activity.length === 0 ? (
            <p className="rounded-lg border border-dashed border-zinc-200 bg-zinc-50/80 px-4 py-8 text-center text-sm text-zinc-600 dark:text-zinc-400">
              Brak zapisów w dzienniku — pojawią się po logowaniu, zapisach na mecze, statystykach i
              innych operacjach w aplikacji.
            </p>
          ) : (
            <ul className="space-y-3">
              {activity.map((item, i) => (
                <li
                  key={`${item.time}-${i}`}
                  className="flex flex-col gap-1 border-l-2 border-emerald-200 pl-4 sm:flex-row sm:items-start sm:justify-between sm:gap-4"
                >
                  <div className="min-w-0 flex-1 space-y-0.5">
                    <p className="text-sm font-medium text-zinc-900">
                      {item.actorLabel ?? item.actorName ?? "—"}
                    </p>
                    <p className="text-sm text-zinc-600 dark:text-zinc-400">{item.text}</p>
                  </div>
                  <time
                    className="shrink-0 text-xs tabular-nums text-zinc-500 dark:text-zinc-400 sm:pt-0.5"
                    dateTime={item.time}
                    title={item.time}
                  >
                    {item.timeDisplay ?? item.time}
                  </time>
                </li>
              ))}
            </ul>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

function UsersView({
  users,
  loading,
  onReload,
}: {
  users: UserRow[];
  loading: boolean;
  onReload: () => void;
}) {
  const [edit, setEdit] = useState<UserRow | null>(null);
  const [createOpen, setCreateOpen] = useState(false);
  const [delUser, setDelUser] = useState<UserRow | null>(null);
  const [q, setQ] = useState("");

  const filtered = useMemo(() => {
    const s = q.trim().toLowerCase();
    if (!s) return users;
    return users.filter(
      (u) =>
        u.first_name.toLowerCase().includes(s) ||
        u.last_name.toLowerCase().includes(s) ||
        u.zawodnik.toLowerCase().includes(s) ||
        String(u.id).includes(s)
    );
  }, [users, q]);

  return (
    <div>
      <Toolbar
        title="Użytkownicy"
        description="Dodawanie kont, edycja danych, rola administratora oraz usuwanie."
        onReload={onReload}
        loading={loading}
      >
        <Button type="button" size="sm" onClick={() => setCreateOpen(true)}>
          <UserPlus className="mr-2 h-4 w-4" aria-hidden />
          Dodaj użytkownika
        </Button>
        <div className="relative w-full min-w-[200px] sm:w-64">
          <Search
            className="pointer-events-none absolute left-2.5 top-1/2 h-4 w-4 -translate-y-1/2 text-zinc-400"
            aria-hidden
          />
          <Input
            className="border-zinc-200 bg-white dark:border-zinc-600 dark:bg-zinc-800 pl-9"
            placeholder="Szukaj…"
            value={q}
            onChange={(e) => setQ(e.target.value)}
            aria-label="Filtruj użytkowników"
          />
        </div>
      </Toolbar>

      <div className="overflow-hidden rounded-xl border border-zinc-200/80 bg-white shadow-sm dark:border-zinc-700/80 dark:bg-zinc-900/90 dark:shadow-black/30">
        <Table>
          <TableHeader>
            <TableRow className="border-zinc-200 hover:bg-transparent">
              <TableHead className="w-12 text-zinc-700" />
              <TableHead className="text-zinc-700">Zawodnik</TableHead>
              <TableHead className="text-zinc-700">PIN</TableHead>
              <TableHead className="text-zinc-700">Rola</TableHead>
              <TableHead className="text-right text-zinc-700">Akcje</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {filtered.length === 0 ? (
              <TableRow>
                <TableCell colSpan={5} className="h-24 text-center text-sm text-zinc-500 dark:text-zinc-400">
                  {users.length === 0
                    ? "Brak użytkowników w bazie."
                    : "Brak wyników dla podanego filtra."}
                </TableCell>
              </TableRow>
            ) : (
              filtered.map((u) => (
                <TableRow key={u.id} className="border-zinc-100">
                  <TableCell className="align-middle">
                    <PlayerAvatar
                      photoPath={u.profile_photo_path}
                      firstName={u.first_name}
                      lastName={u.last_name}
                      size="sm"
                      ringClassName="ring-2 ring-zinc-200"
                    />
                  </TableCell>
                  <TableCell className="align-middle">
                    <PlayerNameStack
                      firstName={u.first_name}
                      lastName={u.last_name}
                      nick={u.zawodnik}
                    />
                  </TableCell>
                  <TableCell className="align-middle">
                    <div className="flex flex-wrap items-center gap-1.5">
                      {(u.pin_set ?? 0) === 1 ? (
                        <Badge variant="secondary" className="font-normal">
                          Ustawiony
                        </Badge>
                      ) : (
                        <Badge variant="outline" className="border-amber-300 bg-amber-50 text-amber-950">
                          Brak PIN
                        </Badge>
                      )}
                      {(u.pin_reset_requested ?? 0) === 1 ? (
                        <Badge className="bg-red-600 font-normal text-white hover:bg-red-600">
                          {(u.pin_change_pending ?? 0) === 1
                            ? "Nowy PIN — czeka"
                            : "Prośba o reset"}
                        </Badge>
                      ) : null}
                    </div>
                  </TableCell>
                  <TableCell>
                    {u.role === "admin" ? (
                      <Badge>Administrator</Badge>
                    ) : (
                      <Badge variant="secondary">Gracz</Badge>
                    )}
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex flex-wrap justify-end gap-2">
                      {(u.pin_change_pending ?? 0) === 1 ? (
                        <>
                          <Button
                            size="sm"
                            className="bg-emerald-600 text-white hover:bg-emerald-700"
                            onClick={async () => {
                              const ok = window.confirm(
                                `Zatwierdzić nowy PIN dla ${u.first_name} ${u.last_name}? Od tej chwili będzie obowiązywał tylko nowy PIN (stary przestanie działać).`
                              );
                              if (!ok) return;
                              const res = await fetch(API.approvePinChange(u.id), {
                                method: "POST",
                              });
                              if (!res.ok) {
                                const j = (await res.json().catch(() => ({}))) as { error?: string };
                                toast.error(
                                  typeof j.error === "string" ? j.error : "Nie udało się zatwierdzić"
                                );
                                return;
                              }
                              toast.success("Nowy PIN został zatwierdzony");
                              onReload();
                            }}
                          >
                            Akceptuj PIN
                          </Button>
                          <Button
                            size="sm"
                            variant="outline"
                            className="border-amber-300 text-amber-950 hover:bg-amber-50"
                            onClick={async () => {
                              const ok = window.confirm(
                                `Odrzucić proponowany PIN dla ${u.first_name} ${u.last_name}? Pozostanie dotychczasowy PIN.`
                              );
                              if (!ok) return;
                              const res = await fetch(API.rejectPinChange(u.id), { method: "POST" });
                              if (!res.ok) {
                                const j = (await res.json().catch(() => ({}))) as { error?: string };
                                toast.error(
                                  typeof j.error === "string" ? j.error : "Nie udało się odrzucić"
                                );
                                return;
                              }
                              toast.success("Odrzucono — aktywny PIN bez zmian");
                              onReload();
                            }}
                          >
                            Odrzuć PIN
                          </Button>
                        </>
                      ) : null}
                      <Button
                        size="sm"
                        variant="outline"
                        className="border-red-200 text-red-800 hover:bg-red-50"
                        onClick={async () => {
                          const ok = window.confirm(
                            `Zresetować PIN dla ${u.first_name} ${u.last_name}? Użytkownik będzie musiał ustawić nowy PIN przy logowaniu.`
                          );
                          if (!ok) return;
                          const res = await fetch(API.resetPin(u.id), { method: "POST" });
                          if (!res.ok) {
                            toast.error("Nie udało się zresetować PIN-u");
                            return;
                          }
                          toast.success("PIN został zresetowany");
                          onReload();
                        }}
                      >
                        Resetuj PIN
                      </Button>
                      <Button size="sm" variant="secondary" onClick={() => setEdit(u)}>
                        Edytuj
                      </Button>
                      <Button size="sm" variant="destructive" onClick={() => setDelUser(u)}>
                        Usuń
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      <Dialog open={Boolean(edit)} onOpenChange={(o) => !o && setEdit(null)}>
        <DialogContent className="sm:max-w-md">
          {edit && (
            <UserEditForm
              user={edit}
              onClose={() => setEdit(null)}
              onSaved={() => {
                setEdit(null);
                onReload();
              }}
            />
          )}
        </DialogContent>
      </Dialog>

      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
        <DialogContent className="sm:max-w-md">
          <UserCreateForm
            onClose={() => setCreateOpen(false)}
            onCreated={() => {
              setCreateOpen(false);
              onReload();
            }}
          />
        </DialogContent>
      </Dialog>

      <Dialog open={delUser != null} onOpenChange={(o) => !o && setDelUser(null)}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Usunąć użytkownika?</DialogTitle>
          </DialogHeader>
          {delUser && (
            <p className="text-sm text-zinc-600 dark:text-zinc-400">
              Konto{" "}
              <strong>
                {delUser.first_name} {delUser.last_name}
              </strong>{" "}
              ({delUser.zawodnik}, id {delUser.id}) zostanie trwale usunięte.
            </p>
          )}
          <DialogFooter className="gap-2 sm:gap-0">
            <Button variant="outline" onClick={() => setDelUser(null)}>
              Anuluj
            </Button>
            <Button
              variant="destructive"
              onClick={async () => {
                if (delUser == null) return;
                const res = await fetch(API.user(delUser.id), { method: "DELETE" });
                if (!res.ok) {
                  toast.error("Nie udało się usunąć użytkownika");
                  return;
                }
                toast.success("Użytkownik został usunięty");
                setDelUser(null);
                onReload();
              }}
            >
              Usuń
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function UserCreateForm({
  onClose,
  onCreated,
}: {
  onClose: () => void;
  onCreated: () => void;
}) {
  const [first_name, setFn] = useState("");
  const [last_name, setLn] = useState("");
  const [zawodnik, setZ] = useState("");
  const [role, setRole] = useState<"admin" | "player">("player");
  const [saving, setSaving] = useState(false);

  return (
    <>
      <DialogHeader>
        <DialogTitle>Nowy użytkownik</DialogTitle>
      </DialogHeader>
      <p className="text-sm text-zinc-600 dark:text-zinc-400">
        Logowanie odbywa się imieniem, nazwiskiem i PIN-em. Piłkarz (awatar) jest przypisywany tutaj —
        użytkownik ustawi PIN przy pierwszym logowaniu (jak przy rejestracji samodzielnej).
      </p>
      <div className="space-y-3 py-2">
        <div>
          <Label htmlFor="adm-new-fn">Imię</Label>
          <Input
            id="adm-new-fn"
            className="mt-1 border-zinc-200"
            value={first_name}
            onChange={(e) => setFn(e.target.value)}
            autoComplete="off"
          />
        </div>
        <div>
          <Label htmlFor="adm-new-ln">Nazwisko</Label>
          <Input
            id="adm-new-ln"
            className="mt-1 border-zinc-200"
            value={last_name}
            onChange={(e) => setLn(e.target.value)}
            autoComplete="off"
          />
        </div>
        <PlayerAliasPicker
          label="Pseudonim zawodnika (awatar)"
          value={zawodnik}
          onChange={setZ}
          helperText="Wyszukaj piłkarza w internecie lub wpisz własny pseudonim — musi być unikalny w akademii."
          inputClassName="border-zinc-200"
        />
        <div>
          <Label>Rola</Label>
          <Select value={role} onValueChange={(v) => setRole(v as "admin" | "player")}>
            <SelectTrigger className="mt-1 border-zinc-200">
              <SelectValue placeholder="Wybierz rolę" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="admin">Administrator</SelectItem>
              <SelectItem value="player">Gracz</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>
      <DialogFooter className="gap-2 sm:gap-0">
        <Button variant="outline" onClick={onClose} disabled={saving}>
          Anuluj
        </Button>
        <Button
          disabled={saving || !zawodnik.trim()}
          onClick={async () => {
            if (!first_name.trim() || !last_name.trim() || !zawodnik) {
              toast.error("Uzupełnij imię, nazwisko i pseudonim");
              return;
            }
            setSaving(true);
            try {
              const res = await fetch(API.users, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                  first_name: first_name.trim(),
                  last_name: last_name.trim(),
                  zawodnik,
                  role,
                }),
              });
              const data = (await res.json().catch(() => ({}))) as { error?: string };
              if (!res.ok) {
                toast.error(data.error ?? "Nie udało się utworzyć konta");
                return;
              }
              toast.success("Utworzono konto użytkownika");
              onCreated();
            } finally {
              setSaving(false);
            }
          }}
        >
          {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" aria-hidden /> : null}
          Utwórz konto
        </Button>
      </DialogFooter>
    </>
  );
}

function UserEditForm({
  user,
  onClose,
  onSaved,
}: {
  user: UserRow;
  onClose: () => void;
  onSaved: () => void;
}) {
  const [first_name, setFn] = useState(user.first_name);
  const [last_name, setLn] = useState(user.last_name);
  const [zawodnik, setZ] = useState(user.zawodnik);
  const [role, setRole] = useState(user.role);
  const [saving, setSaving] = useState(false);

  return (
    <>
      <DialogHeader>
        <DialogTitle>Edytuj użytkownika</DialogTitle>
      </DialogHeader>
      <div className="space-y-3 py-2">
        <div>
          <Label htmlFor="adm-fn">Imię</Label>
          <Input
            id="adm-fn"
            className="mt-1 border-zinc-200"
            value={first_name}
            onChange={(e) => setFn(e.target.value)}
          />
        </div>
        <div>
          <Label htmlFor="adm-ln">Nazwisko</Label>
          <Input
            id="adm-ln"
            className="mt-1 border-zinc-200"
            value={last_name}
            onChange={(e) => setLn(e.target.value)}
          />
        </div>
        <div>
          <Label htmlFor="adm-alias">Pseudonim zawodnika</Label>
          <Input
            id="adm-alias"
            className="mt-1 border-zinc-200"
            value={zawodnik}
            onChange={(e) => setZ(e.target.value)}
          />
        </div>
        <div>
          <Label>Rola</Label>
          <Select value={role} onValueChange={setRole}>
            <SelectTrigger className="mt-1 border-zinc-200">
              <SelectValue placeholder="Wybierz rolę" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="admin">Administrator</SelectItem>
              <SelectItem value="player">Gracz</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>
      <DialogFooter className="gap-2 sm:gap-0">
        <Button variant="outline" onClick={onClose} disabled={saving}>
          Anuluj
        </Button>
        <Button
          disabled={saving}
          onClick={async () => {
            setSaving(true);
            try {
              const res = await fetch(API.user(user.id), {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ first_name, last_name, zawodnik, role }),
              });
              if (!res.ok) {
                toast.error("Nie udało się zapisać zmian");
                return;
              }
              toast.success("Zapisano dane użytkownika");
              onSaved();
            } finally {
              setSaving(false);
            }
          }}
        >
          {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" aria-hidden /> : null}
          Zapisz
        </Button>
      </DialogFooter>
    </>
  );
}

function MatchEditDialogContent({
  match,
  onEdited,
}: {
  match: MatchRow;
  onEdited: () => void;
}) {
  const [maxSlots, setMaxSlots] = useState(String(match.max_slots || 14));
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    const slots = Number(maxSlots);
    if (!Number.isFinite(slots) || slots < 1) {
      toast.error("Liczba miejsc musi być większa niż 0");
      return;
    }

    setSaving(true);
    try {
      const res = await fetch(API.match(match.id), {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          date: match.date,
          time: match.time,
          location: match.location,
          max_slots: slots,
        }),
      });

      const data = (await res.json().catch(() => ({}))) as { error?: string };

      if (!res.ok) {
        toast.error(data.error ?? "Nie udało się zapisać");
        return;
      }

      toast.success("Mecz został zaktualizowany");
      onEdited();
    } catch {
      toast.error("Błąd podczas zapisu");
    } finally {
      setSaving(false);
    }
  };

  return (
    <>
      <div className="space-y-4 py-2">
        <p className="text-sm text-zinc-600 dark:text-zinc-400">
          <strong>{match.date}</strong> o <strong>{match.time}</strong>, <strong>{match.location}</strong>
        </p>
        <div>
          <Label htmlFor="max-slots">Maksymalna liczba miejsc</Label>
          <Input
            id="max-slots"
            type="number"
            min="1"
            value={maxSlots}
            onChange={(e) => setMaxSlots(e.target.value)}
            className="mt-1 border-zinc-200"
            disabled={saving}
          />
          <p className="mt-1 text-xs text-zinc-500">
            Obecnie zapisanych: <strong>{match.players_count}</strong>
          </p>
        </div>
      </div>
      <DialogFooter className="gap-2 sm:gap-0">
        <Button variant="outline" disabled={saving}>
          Zamknij
        </Button>
        <Button onClick={handleSave} disabled={saving}>
          {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" aria-hidden /> : null}
          Zapisz zmiany
        </Button>
      </DialogFooter>
    </>
  );
}

import { createClient, type Client, type InArgs, type Row } from "@libsql/client";
import Database from "better-sqlite3";
import fs from "fs";
import * as path from "path";
import { isVercel, resolveDatabaseFilePath } from "@/lib/runtime-paths";
import { initLibsqlSchema } from "@/lib/turso-init-schema";
import { withTransientNetworkRetries } from "@/lib/transient-network-retry";

/** Lokalny plik SQLite (dev) lub Turso (gdy TURSO_DATABASE_URL). */
export type AppDb = {
  prepare(sql: string): {
    run(...params: unknown[]): Promise<{ lastInsertRowid: bigint }>;
    get<T = unknown>(...params: unknown[]): Promise<T | undefined>;
    all<T = unknown>(...params: unknown[]): Promise<T[]>;
  };
  exec(sql: string): Promise<void>;
};

function hasTursoEnv(): boolean {
  return Boolean(process.env.TURSO_DATABASE_URL?.trim());
}

let sqliteInstance: Database.Database | null = null;
let libsqlClient: Client | null = null;
let libsqlSchemaReady = false;

function rowToRecord(row: Row, columns: string[]): Record<string, unknown> {
  const o: Record<string, unknown> = {};
  for (const c of columns) {
    o[c] = row[c];
  }
  return o;
}

function createSqliteFacade(db: Database.Database): AppDb {
  return {
    prepare(sql: string) {
      const stmt = db.prepare(sql);
      return {
        run(...params: unknown[]) {
          const r = stmt.run(...(params as never[]));
          return Promise.resolve({
            lastInsertRowid: BigInt(r.lastInsertRowid ?? 0),
          });
        },
        get<T = unknown>(...params: unknown[]) {
          return Promise.resolve(stmt.get(...(params as never[])) as T | undefined);
        },
        all<T = unknown>(...params: unknown[]) {
          return Promise.resolve(stmt.all(...(params as never[])) as T[]);
        },
      };
    },
    exec(sql: string) {
      db.exec(sql);
      return Promise.resolve();
    },
  };
}

/** Stare bazy: CHECK(slot_index <= 6) — potrzebne do 8 pozycji na połowę. */
function migrateMatchLineupSlotsSlotIndexMax(db: Database.Database) {
  const row = db
    .prepare(`SELECT sql FROM sqlite_master WHERE type='table' AND name='match_lineup_slots'`)
    .get() as { sql: string } | undefined;
  if (!row?.sql || row.sql.includes("slot_index <= 7")) return;
  if (!row.sql.includes("slot_index <= 6")) return;

  db.exec(`
    CREATE TABLE match_lineup_slots_migration (
      match_id INTEGER NOT NULL,
      team TEXT NOT NULL CHECK (team IN ('home', 'away')),
      slot_index INTEGER NOT NULL CHECK (slot_index >= 0 AND slot_index <= 7),
      user_id INTEGER NOT NULL,
      PRIMARY KEY (match_id, team, slot_index),
      FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
      FOREIGN KEY (user_id) REFERENCES users(id)
    );
    INSERT INTO match_lineup_slots_migration SELECT * FROM match_lineup_slots;
    DROP TABLE match_lineup_slots;
    ALTER TABLE match_lineup_slots_migration RENAME TO match_lineup_slots;
  `);
}

function createLibsqlFacade(client: Client): AppDb {
  return {
    prepare(sql: string) {
      return {
        async run(...params: unknown[]) {
          const rs = await client.execute({ sql, args: params as InArgs });
          return { lastInsertRowid: rs.lastInsertRowid ?? BigInt(0) };
        },
        async get<T = unknown>(...params: unknown[]) {
          const rs = await client.execute({ sql, args: params as InArgs });
          if (rs.rows.length === 0) return undefined;
          return rowToRecord(rs.rows[0], rs.columns) as T;
        },
        async all<T = unknown>(...params: unknown[]) {
          const rs = await client.execute({ sql, args: params as InArgs });
          return rs.rows.map((row) => rowToRecord(row, rs.columns) as T);
        },
      };
    },
    exec(sql: string) {
      return client.executeMultiple(sql);
    },
  };
}

function initSchemaSync(db: Database.Database) {
  db.exec(`
    CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      first_name TEXT NOT NULL,
      last_name TEXT NOT NULL,
      player_alias TEXT UNIQUE NOT NULL,
      is_admin INTEGER DEFAULT 0
    );

    CREATE TABLE IF NOT EXISTS matches (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      match_date TEXT NOT NULL,
      match_time TEXT NOT NULL,
      location TEXT NOT NULL,
      max_slots INTEGER NOT NULL,
      signed_up INTEGER NOT NULL DEFAULT 0,
      played INTEGER NOT NULL DEFAULT 0
    );

    CREATE TABLE IF NOT EXISTS match_signups (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      match_id INTEGER NOT NULL,
      paid INTEGER NOT NULL DEFAULT 0,
      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY(user_id) REFERENCES users(id),
      FOREIGN KEY(match_id) REFERENCES matches(id)
    );

    CREATE TABLE IF NOT EXISTS match_stats (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      match_id INTEGER NOT NULL,
      goals INTEGER DEFAULT 0,
      assists INTEGER DEFAULT 0,
      distance REAL DEFAULT 0,
      saves INTEGER NOT NULL DEFAULT 0,
      FOREIGN KEY(user_id) REFERENCES users(id),
      FOREIGN KEY(match_id) REFERENCES matches(id)
    );

    CREATE TABLE IF NOT EXISTS activity_log (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER,
      action TEXT NOT NULL,
      timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY(user_id) REFERENCES users(id)
    );

    CREATE TABLE IF NOT EXISTS page_views (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      screen_key TEXT NOT NULL,
      pathname TEXT NOT NULL,
      user_id INTEGER,
      visitor_id TEXT NOT NULL,
      created_at TEXT NOT NULL,
      FOREIGN KEY(user_id) REFERENCES users(id)
    );

    CREATE INDEX IF NOT EXISTS idx_page_views_created ON page_views(created_at);
    CREATE INDEX IF NOT EXISTS idx_page_views_screen_created ON page_views(screen_key, created_at);
    CREATE INDEX IF NOT EXISTS idx_page_views_user_created ON page_views(user_id, created_at);

    CREATE INDEX IF NOT EXISTS idx_matches_played_date_time ON matches(played, match_date, match_time);

    CREATE TABLE IF NOT EXISTS match_lineup_slots (
      match_id INTEGER NOT NULL,
      team TEXT NOT NULL CHECK (team IN ('home', 'away')),
      slot_index INTEGER NOT NULL CHECK (slot_index >= 0 AND slot_index <= 7),
      user_id INTEGER NOT NULL,
      PRIMARY KEY (match_id, team, slot_index),
      FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
      FOREIGN KEY (user_id) REFERENCES users(id)
    );

    CREATE TABLE IF NOT EXISTS app_settings (
      id INTEGER PRIMARY KEY CHECK (id = 1),
      match_notification_prompt_enabled INTEGER NOT NULL DEFAULT 0,
      home_youtube_url TEXT
    );

    CREATE TABLE IF NOT EXISTS wallet_deposit_requests (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      amount_pln REAL NOT NULL,
      created_by TEXT NOT NULL CHECK (created_by IN ('player','admin')),
      status TEXT NOT NULL CHECK (status IN ('pending','completed','cancelled')) DEFAULT 'pending',
      note TEXT,
      player_declared_at TEXT,
      admin_confirmed_received_at TEXT,
      admin_declared_received_at TEXT,
      player_confirmed_amount_at TEXT,
      completed_at TEXT,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      FOREIGN KEY (user_id) REFERENCES users(id)
    );
    CREATE INDEX IF NOT EXISTS idx_wallet_deposit_requests_status_created
    ON wallet_deposit_requests(status, created_at);
    CREATE INDEX IF NOT EXISTS idx_wallet_deposit_requests_user_created
    ON wallet_deposit_requests(user_id, created_at);

    CREATE TABLE IF NOT EXISTS wallet_transactions (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      kind TEXT NOT NULL CHECK (kind IN ('deposit','match_charge','adjustment')),
      amount_pln REAL NOT NULL,
      deposit_request_id INTEGER,
      match_id INTEGER,
      note TEXT,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      FOREIGN KEY (user_id) REFERENCES users(id),
      FOREIGN KEY (deposit_request_id) REFERENCES wallet_deposit_requests(id),
      FOREIGN KEY (match_id) REFERENCES matches(id)
    );
    CREATE INDEX IF NOT EXISTS idx_wallet_transactions_user_created
    ON wallet_transactions(user_id, created_at);
    CREATE INDEX IF NOT EXISTS idx_wallet_transactions_match
    ON wallet_transactions(match_id);

    CREATE TABLE IF NOT EXISTS match_wallet_charges (
      match_id INTEGER NOT NULL,
      user_id INTEGER NOT NULL,
      amount_pln REAL NOT NULL,
      note TEXT,
      created_by_admin_id INTEGER NOT NULL,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (match_id, user_id),
      FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
      FOREIGN KEY (user_id) REFERENCES users(id),
      FOREIGN KEY (created_by_admin_id) REFERENCES users(id)
    );
    CREATE INDEX IF NOT EXISTS idx_match_wallet_charges_match_created
    ON match_wallet_charges(match_id, created_at);

    CREATE TABLE IF NOT EXISTS public_share_links (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      token TEXT NOT NULL UNIQUE,
      kind TEXT NOT NULL CHECK (kind IN ('last_match_wallets')),
      created_by_admin_id INTEGER NOT NULL,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      expires_at TEXT,
      revoked_at TEXT,
      FOREIGN KEY (created_by_admin_id) REFERENCES users(id)
    );
    CREATE INDEX IF NOT EXISTS idx_public_share_links_kind_created
    ON public_share_links(kind, created_at);
  `);

  const cols = db.prepare("PRAGMA table_info(match_stats)").all() as { name: string }[];
  if (!cols.some((c) => c.name === "saves")) {
    db.exec("ALTER TABLE match_stats ADD COLUMN saves INTEGER NOT NULL DEFAULT 0");
  }

   const matchCols = db.prepare("PRAGMA table_info(matches)").all() as { name: string }[];
   if (!matchCols.some((c) => c.name === "lineup_public")) {
     db.exec("ALTER TABLE matches ADD COLUMN lineup_public INTEGER NOT NULL DEFAULT 0");
   }
   if (!matchCols.some((c) => c.name === "fee_pln")) {
     db.exec("ALTER TABLE matches ADD COLUMN fee_pln REAL");
   }
   if (!matchCols.some((c) => c.name === "cancelled")) {
     db.exec("ALTER TABLE matches ADD COLUMN cancelled INTEGER NOT NULL DEFAULT 0");
   }
   if (!matchCols.some((c) => c.name === "cancellation_reason")) {
     db.exec("ALTER TABLE matches ADD COLUMN cancellation_reason TEXT");
   }

  const userCols = db.prepare("PRAGMA table_info(users)").all() as { name: string }[];
  if (!userCols.some((c) => c.name === "profile_photo_path")) {
    db.exec("ALTER TABLE users ADD COLUMN profile_photo_path TEXT");
  }
  if (!userCols.some((c) => c.name === "email")) {
    db.exec("ALTER TABLE users ADD COLUMN email TEXT");
  }
  if (!userCols.some((c) => c.name === "match_notifications_consent")) {
    db.exec("ALTER TABLE users ADD COLUMN match_notifications_consent INTEGER NOT NULL DEFAULT 0");
  }
  if (!userCols.some((c) => c.name === "notification_prompt_completed")) {
    db.exec("ALTER TABLE users ADD COLUMN notification_prompt_completed INTEGER NOT NULL DEFAULT 0");
    db.prepare("UPDATE users SET notification_prompt_completed = 1").run();
  }
  if (!userCols.some((c) => c.name === "pin_hash")) {
    db.exec("ALTER TABLE users ADD COLUMN pin_hash TEXT");
  }
  if (!userCols.some((c) => c.name === "pin_reset_requested")) {
    db.exec("ALTER TABLE users ADD COLUMN pin_reset_requested INTEGER NOT NULL DEFAULT 0");
  }
  if (!userCols.some((c) => c.name === "auth_version")) {
    db.exec("ALTER TABLE users ADD COLUMN auth_version INTEGER NOT NULL DEFAULT 0");
  }
  if (!userCols.some((c) => c.name === "pin_hash_pending")) {
    db.exec("ALTER TABLE users ADD COLUMN pin_hash_pending TEXT");
  }
  if (!userCols.some((c) => c.name === "ui_theme")) {
    db.exec("ALTER TABLE users ADD COLUMN ui_theme TEXT NOT NULL DEFAULT 'light'");
  }

  const signupCols = db.prepare("PRAGMA table_info(match_signups)").all() as { name: string }[];
  if (!signupCols.some((c) => c.name === "drives_car")) {
    db.exec("ALTER TABLE match_signups ADD COLUMN drives_car INTEGER NOT NULL DEFAULT 0");
  }
  if (!signupCols.some((c) => c.name === "can_take_passengers")) {
    db.exec("ALTER TABLE match_signups ADD COLUMN can_take_passengers INTEGER NOT NULL DEFAULT 0");
  }
  if (!signupCols.some((c) => c.name === "needs_transport")) {
    db.exec("ALTER TABLE match_signups ADD COLUMN needs_transport INTEGER NOT NULL DEFAULT 0");
  }
  if (!signupCols.some((c) => c.name === "commitment")) {
    db.exec("ALTER TABLE match_signups ADD COLUMN commitment INTEGER NOT NULL DEFAULT 1");
  }

  migrateMatchLineupSlotsSlotIndexMax(db);

  db.exec(`
    CREATE TABLE IF NOT EXISTS match_transport_messages (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      match_id INTEGER NOT NULL,
      user_id INTEGER NOT NULL,
      body TEXT NOT NULL,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
      FOREIGN KEY (user_id) REFERENCES users(id)
    );
  `);
  db.exec(`
    CREATE INDEX IF NOT EXISTS idx_transport_msg_match_created
    ON match_transport_messages(match_id, created_at);
  `);
  db.exec(`
    CREATE TABLE IF NOT EXISTS match_participation_survey (
      user_id INTEGER NOT NULL,
      match_id INTEGER NOT NULL,
      played INTEGER NOT NULL,
      answered_at TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (user_id, match_id),
      FOREIGN KEY (user_id) REFERENCES users(id),
      FOREIGN KEY (match_id) REFERENCES matches(id)
    );
    CREATE INDEX IF NOT EXISTS idx_match_participation_survey_match
    ON match_participation_survey(match_id);
  `);
  db.exec(`
    CREATE TABLE IF NOT EXISTS match_attendance (
      match_id INTEGER NOT NULL,
      user_id INTEGER NOT NULL,
      present INTEGER NOT NULL,
      marked_by_admin_id INTEGER NOT NULL,
      marked_at TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (match_id, user_id),
      FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
      FOREIGN KEY (user_id) REFERENCES users(id),
      FOREIGN KEY (marked_by_admin_id) REFERENCES users(id)
    );
    CREATE INDEX IF NOT EXISTS idx_match_attendance_match
    ON match_attendance(match_id);
  `);
  db.exec(`
    CREATE TABLE IF NOT EXISTS participation_survey_answer (
      user_id INTEGER NOT NULL,
      survey_key TEXT NOT NULL,
      played INTEGER NOT NULL,
      answered_at TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (user_id, survey_key),
      FOREIGN KEY (user_id) REFERENCES users(id)
    );
    CREATE TABLE IF NOT EXISTS standalone_match_stats (
      user_id INTEGER NOT NULL,
      survey_key TEXT NOT NULL,
      goals INTEGER NOT NULL DEFAULT 0,
      assists INTEGER NOT NULL DEFAULT 0,
      distance REAL NOT NULL DEFAULT 0,
      saves INTEGER NOT NULL DEFAULT 0,
      updated_at TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (user_id, survey_key),
      FOREIGN KEY (user_id) REFERENCES users(id)
    );
  `);

  const appSettingsCols = db.prepare("PRAGMA table_info(app_settings)").all() as { name: string }[];
  if (!appSettingsCols.some((c) => c.name === "home_youtube_url")) {
    db.exec("ALTER TABLE app_settings ADD COLUMN home_youtube_url TEXT");
  }

  // Upewnij się, że istnieje pojedynczy wiersz z ustawieniami (id=1).
  const hasSettings = db.prepare("SELECT 1 AS ok FROM app_settings WHERE id = 1").get() as
    | { ok: 1 }
    | undefined;
  if (!hasSettings) {
    db.prepare("INSERT INTO app_settings (id, match_notification_prompt_enabled) VALUES (1, 0)").run();
  }
}

/**
 * Jedna instancja bazy na proces (lokalny plik lub klient Turso).
 * Na Vercelu wymagane jest `TURSO_DATABASE_URL` — lokalny plik w /tmp nie jest współdzielony między instancjami.
 */
export async function getDb(): Promise<AppDb> {
  if (isVercel() && !hasTursoEnv()) {
    throw new Error(
      "Na Vercelu ustaw TURSO_DATABASE_URL (oraz TURSO_AUTH_TOKEN z panelu Turso). Lokalny plik SQLite nie działa poprawnie na serverless."
    );
  }

  if (hasTursoEnv()) {
    if (!libsqlClient) {
      libsqlClient = createClient({
        url: process.env.TURSO_DATABASE_URL!,
        authToken: process.env.TURSO_AUTH_TOKEN?.trim() || undefined,
      });
    }
    if (!libsqlSchemaReady) {
      await withTransientNetworkRetries(
        async () => {
          await initLibsqlSchema(libsqlClient!);
        },
        {
          onBeforeRetry: () => {
            libsqlClient?.close();
            libsqlClient = createClient({
              url: process.env.TURSO_DATABASE_URL!,
              authToken: process.env.TURSO_AUTH_TOKEN?.trim() || undefined,
            });
          },
        }
      );
      libsqlSchemaReady = true;
    }
    return createLibsqlFacade(libsqlClient);
  }

  if (!sqliteInstance) {
    const p = resolveDatabaseFilePath();
    fs.mkdirSync(path.dirname(p), { recursive: true });
    sqliteInstance = new Database(p);
    sqliteInstance.pragma(isVercel() ? "journal_mode = DELETE" : "journal_mode = WAL");
    initSchemaSync(sqliteInstance);
  }
  return createSqliteFacade(sqliteInstance);
}

export async function logActivity(userId: number | null, action: string) {
  const db = await getDb();
  await db.prepare("INSERT INTO activity_log (user_id, action) VALUES (?, ?)").run(userId, action);
}

export type UserRow = {
  id: number;
  first_name: string;
  last_name: string;
  player_alias: string;
  is_admin: number;
  profile_photo_path?: string | null;
  /** Adres do powiadomień o meczach (opcjonalny). */
  email?: string | null;
  /** 1 = zgoda na e‑maile o nowych terminach. */
  match_notifications_consent?: number;
  /** 1 = użytkownik udzielił odpowiedzi w oknie powitalnym (nie pokazuj ponownie). */
  notification_prompt_completed?: number;
  /** Skrót bcrypt PIN-u; NULL = wymagane ustawienie przy pierwszym logowaniu lub po resecie. */
  pin_hash?: string | null;
  /** 1 = użytkownik zgłosił „zapomniałem PIN-u” (widoczne dla admina). */
  pin_reset_requested?: number;
  /** Wersja sesji — inkrementacja unieważnia istniejące JWT (np. reset PIN przez admina). */
  auth_version?: number;
  /** Propozycja nowego PIN-u (bcrypt); oczekuje na zatwierdzenie przez admina. */
  pin_hash_pending?: string | null;
  /** Motyw interfejsu: jasny lub ciemny. */
  ui_theme?: string | null;
};

export type MatchRow = {
  id: number;
  match_date: string;
  match_time: string;
  location: string;
  max_slots: number;
  signed_up: number;
  played: number;
  lineup_public: number;
  /** Kwota wpisowego za mecz (PLN); ustawiana przez administratora. */
  fee_pln?: number | null;
  /** 1 = mecz został anulowany. */
  cancelled?: number;
  /** Powód anulacji meczu. */
  cancellation_reason?: string | null;
};

import { createClient, type Client, type InArgs, type Row } from "@libsql/client";
import Database from "better-sqlite3";
import fs from "fs";
import * as path from "path";
import { isVercel, resolveDatabaseFilePath } from "@/lib/runtime-paths";
import { initLibsqlSchema } from "@/lib/turso-init-schema";
import { withTransientNetworkRetries } from "@/lib/transient-network-retry";

/** Lokalny plik SQLite (dev) lub Turso (gdy TURSO_DATABASE_URL). */
export type AppDb = {
  prepare(sql: string): {
    run(...params: unknown[]): Promise<{ lastInsertRowid: bigint }>;
    get<T = unknown>(...params: unknown[]): Promise<T | undefined>;
    all<T = unknown>(...params: unknown[]): Promise<T[]>;
  };
  exec(sql: string): Promise<void>;
};

function hasTursoEnv(): boolean {
  return Boolean(process.env.TURSO_DATABASE_URL?.trim());
}

let sqliteInstance: Database.Database | null = null;
let libsqlClient: Client | null = null;
let libsqlSchemaReady = false;

function rowToRecord(row: Row, columns: string[]): Record<string, unknown> {
  const o: Record<string, unknown> = {};
  for (const c of columns) {
    o[c] = row[c];
  }
  return o;
}

function createSqliteFacade(db: Database.Database): AppDb {
  return {
    prepare(sql: string) {
      const stmt = db.prepare(sql);
      return {
        run(...params: unknown[]) {
          const r = stmt.run(...(params as never[]));
          return Promise.resolve({
            lastInsertRowid: BigInt(r.lastInsertRowid ?? 0),
          });
        },
        get<T = unknown>(...params: unknown[]) {
          return Promise.resolve(stmt.get(...(params as never[])) as T | undefined);
        },
        all<T = unknown>(...params: unknown[]) {
          return Promise.resolve(stmt.all(...(params as never[])) as T[]);
        },
      };
    },
    exec(sql: string) {
      db.exec(sql);
      return Promise.resolve();
    },
  };
}

/** Stare bazy: CHECK(slot_index <= 6) — potrzebne do 8 pozycji na połowę. */
function migrateMatchLineupSlotsSlotIndexMax(db: Database.Database) {
  const row = db
    .prepare(`SELECT sql FROM sqlite_master WHERE type='table' AND name='match_lineup_slots'`)
    .get() as { sql: string } | undefined;
  if (!row?.sql || row.sql.includes("slot_index <= 7")) return;
  if (!row.sql.includes("slot_index <= 6")) return;

  db.exec(`
    CREATE TABLE match_lineup_slots_migration (
      match_id INTEGER NOT NULL,
      team TEXT NOT NULL CHECK (team IN ('home', 'away')),
      slot_index INTEGER NOT NULL CHECK (slot_index >= 0 AND slot_index <= 7),
      user_id INTEGER NOT NULL,
      PRIMARY KEY (match_id, team, slot_index),
      FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
      FOREIGN KEY (user_id) REFERENCES users(id)
    );
    INSERT INTO match_lineup_slots_migration SELECT * FROM match_lineup_slots;
    DROP TABLE match_lineup_slots;
    ALTER TABLE match_lineup_slots_migration RENAME TO match_lineup_slots;
  `);
}

function createLibsqlFacade(client: Client): AppDb {
  return {
    prepare(sql: string) {
      return {
        async run(...params: unknown[]) {
          const rs = await client.execute({ sql, args: params as InArgs });
          return { lastInsertRowid: rs.lastInsertRowid ?? BigInt(0) };
        },
        async get<T = unknown>(...params: unknown[]) {
          const rs = await client.execute({ sql, args: params as InArgs });
          if (rs.rows.length === 0) return undefined;
          return rowToRecord(rs.rows[0], rs.columns) as T;
        },
        async all<T = unknown>(...params: unknown[]) {
          const rs = await client.execute({ sql, args: params as InArgs });
          return rs.rows.map((row) => rowToRecord(row, rs.columns) as T);
        },
      };
    },
    exec(sql: string) {
      return client.executeMultiple(sql);
    },
  };
}

function initSchemaSync(db: Database.Database) {
  db.exec(`
    CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      first_name TEXT NOT NULL,
      last_name TEXT NOT NULL,
      player_alias TEXT UNIQUE NOT NULL,
      is_admin INTEGER DEFAULT 0
    );

    CREATE TABLE IF NOT EXISTS matches (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      match_date TEXT NOT NULL,
      match_time TEXT NOT NULL,
      location TEXT NOT NULL,
      max_slots INTEGER NOT NULL,
      signed_up INTEGER NOT NULL DEFAULT 0,
      played INTEGER NOT NULL DEFAULT 0
    );

    CREATE TABLE IF NOT EXISTS match_signups (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      match_id INTEGER NOT NULL,
      paid INTEGER NOT NULL DEFAULT 0,
      created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY(user_id) REFERENCES users(id),
      FOREIGN KEY(match_id) REFERENCES matches(id)
    );

    CREATE TABLE IF NOT EXISTS match_stats (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      match_id INTEGER NOT NULL,
      goals INTEGER DEFAULT 0,
      assists INTEGER DEFAULT 0,
      distance REAL DEFAULT 0,
      saves INTEGER NOT NULL DEFAULT 0,
      FOREIGN KEY(user_id) REFERENCES users(id),
      FOREIGN KEY(match_id) REFERENCES matches(id)
    );

    CREATE TABLE IF NOT EXISTS activity_log (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER,
      action TEXT NOT NULL,
      timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY(user_id) REFERENCES users(id)
    );

    CREATE TABLE IF NOT EXISTS page_views (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      screen_key TEXT NOT NULL,
      pathname TEXT NOT NULL,
      user_id INTEGER,
      visitor_id TEXT NOT NULL,
      created_at TEXT NOT NULL,
      FOREIGN KEY(user_id) REFERENCES users(id)
    );

    CREATE INDEX IF NOT EXISTS idx_page_views_created ON page_views(created_at);
    CREATE INDEX IF NOT EXISTS idx_page_views_screen_created ON page_views(screen_key, created_at);
    CREATE INDEX IF NOT EXISTS idx_page_views_user_created ON page_views(user_id, created_at);

    CREATE INDEX IF NOT EXISTS idx_matches_played_date_time ON matches(played, match_date, match_time);

    CREATE TABLE IF NOT EXISTS match_lineup_slots (
      match_id INTEGER NOT NULL,
      team TEXT NOT NULL CHECK (team IN ('home', 'away')),
      slot_index INTEGER NOT NULL CHECK (slot_index >= 0 AND slot_index <= 7),
      user_id INTEGER NOT NULL,
      PRIMARY KEY (match_id, team, slot_index),
      FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
      FOREIGN KEY (user_id) REFERENCES users(id)
    );

    CREATE TABLE IF NOT EXISTS app_settings (
      id INTEGER PRIMARY KEY CHECK (id = 1),
      match_notification_prompt_enabled INTEGER NOT NULL DEFAULT 0,
      home_youtube_url TEXT
    );

    CREATE TABLE IF NOT EXISTS wallet_deposit_requests (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      amount_pln REAL NOT NULL,
      created_by TEXT NOT NULL CHECK (created_by IN ('player','admin')),
      status TEXT NOT NULL CHECK (status IN ('pending','completed','cancelled')) DEFAULT 'pending',
      note TEXT,
      player_declared_at TEXT,
      admin_confirmed_received_at TEXT,
      admin_declared_received_at TEXT,
      player_confirmed_amount_at TEXT,
      completed_at TEXT,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      FOREIGN KEY (user_id) REFERENCES users(id)
    );
    CREATE INDEX IF NOT EXISTS idx_wallet_deposit_requests_status_created
    ON wallet_deposit_requests(status, created_at);
    CREATE INDEX IF NOT EXISTS idx_wallet_deposit_requests_user_created
    ON wallet_deposit_requests(user_id, created_at);

    CREATE TABLE IF NOT EXISTS wallet_transactions (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      user_id INTEGER NOT NULL,
      kind TEXT NOT NULL CHECK (kind IN ('deposit','match_charge','adjustment')),
      amount_pln REAL NOT NULL,
      deposit_request_id INTEGER,
      match_id INTEGER,
      note TEXT,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      FOREIGN KEY (user_id) REFERENCES users(id),
      FOREIGN KEY (deposit_request_id) REFERENCES wallet_deposit_requests(id),
      FOREIGN KEY (match_id) REFERENCES matches(id)
    );
    CREATE INDEX IF NOT EXISTS idx_wallet_transactions_user_created
    ON wallet_transactions(user_id, created_at);
    CREATE INDEX IF NOT EXISTS idx_wallet_transactions_match
    ON wallet_transactions(match_id);

    CREATE TABLE IF NOT EXISTS match_wallet_charges (
      match_id INTEGER NOT NULL,
      user_id INTEGER NOT NULL,
      amount_pln REAL NOT NULL,
      note TEXT,
      created_by_admin_id INTEGER NOT NULL,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (match_id, user_id),
      FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
      FOREIGN KEY (user_id) REFERENCES users(id),
      FOREIGN KEY (created_by_admin_id) REFERENCES users(id)
    );
    CREATE INDEX IF NOT EXISTS idx_match_wallet_charges_match_created
    ON match_wallet_charges(match_id, created_at);

    CREATE TABLE IF NOT EXISTS public_share_links (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      token TEXT NOT NULL UNIQUE,
      kind TEXT NOT NULL CHECK (kind IN ('last_match_wallets')),
      created_by_admin_id INTEGER NOT NULL,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      expires_at TEXT,
      revoked_at TEXT,
      FOREIGN KEY (created_by_admin_id) REFERENCES users(id)
    );
    CREATE INDEX IF NOT EXISTS idx_public_share_links_kind_created
    ON public_share_links(kind, created_at);
  `);

  const cols = db.prepare("PRAGMA table_info(match_stats)").all() as { name: string }[];
  if (!cols.some((c) => c.name === "saves")) {
    db.exec("ALTER TABLE match_stats ADD COLUMN saves INTEGER NOT NULL DEFAULT 0");
  }

   const matchCols = db.prepare("PRAGMA table_info(matches)").all() as { name: string }[];
   if (!matchCols.some((c) => c.name === "lineup_public")) {
     db.exec("ALTER TABLE matches ADD COLUMN lineup_public INTEGER NOT NULL DEFAULT 0");
   }
   if (!matchCols.some((c) => c.name === "fee_pln")) {
     db.exec("ALTER TABLE matches ADD COLUMN fee_pln REAL");
   }
   if (!matchCols.some((c) => c.name === "cancelled")) {
     db.exec("ALTER TABLE matches ADD COLUMN cancelled INTEGER NOT NULL DEFAULT 0");
   }
   if (!matchCols.some((c) => c.name === "cancellation_reason")) {
     db.exec("ALTER TABLE matches ADD COLUMN cancellation_reason TEXT");
   }

  const userCols = db.prepare("PRAGMA table_info(users)").all() as { name: string }[];
  if (!userCols.some((c) => c.name === "profile_photo_path")) {
    db.exec("ALTER TABLE users ADD COLUMN profile_photo_path TEXT");
  }
  if (!userCols.some((c) => c.name === "email")) {
    db.exec("ALTER TABLE users ADD COLUMN email TEXT");
  }
  if (!userCols.some((c) => c.name === "match_notifications_consent")) {
    db.exec("ALTER TABLE users ADD COLUMN match_notifications_consent INTEGER NOT NULL DEFAULT 0");
  }
  if (!userCols.some((c) => c.name === "notification_prompt_completed")) {
    db.exec("ALTER TABLE users ADD COLUMN notification_prompt_completed INTEGER NOT NULL DEFAULT 0");
    db.prepare("UPDATE users SET notification_prompt_completed = 1").run();
  }
  if (!userCols.some((c) => c.name === "pin_hash")) {
    db.exec("ALTER TABLE users ADD COLUMN pin_hash TEXT");
  }
  if (!userCols.some((c) => c.name === "pin_reset_requested")) {
    db.exec("ALTER TABLE users ADD COLUMN pin_reset_requested INTEGER NOT NULL DEFAULT 0");
  }
  if (!userCols.some((c) => c.name === "auth_version")) {
    db.exec("ALTER TABLE users ADD COLUMN auth_version INTEGER NOT NULL DEFAULT 0");
  }
  if (!userCols.some((c) => c.name === "pin_hash_pending")) {
    db.exec("ALTER TABLE users ADD COLUMN pin_hash_pending TEXT");
  }
  if (!userCols.some((c) => c.name === "ui_theme")) {
    db.exec("ALTER TABLE users ADD COLUMN ui_theme TEXT NOT NULL DEFAULT 'light'");
  }
  if (!userCols.some((c) => c.name === "is_temporary")) {
    db.exec("ALTER TABLE users ADD COLUMN is_temporary INTEGER NOT NULL DEFAULT 0");
  }
  if (!userCols.some((c) => c.name === "temporary_guest_match_id")) {
    db.exec("ALTER TABLE users ADD COLUMN temporary_guest_match_id INTEGER");
  }

  const signupCols = db.prepare("PRAGMA table_info(match_signups)").all() as { name: string }[];
  if (!signupCols.some((c) => c.name === "drives_car")) {
    db.exec("ALTER TABLE match_signups ADD COLUMN drives_car INTEGER NOT NULL DEFAULT 0");
  }
  if (!signupCols.some((c) => c.name === "can_take_passengers")) {
    db.exec("ALTER TABLE match_signups ADD COLUMN can_take_passengers INTEGER NOT NULL DEFAULT 0");
  }
  if (!signupCols.some((c) => c.name === "needs_transport")) {
    db.exec("ALTER TABLE match_signups ADD COLUMN needs_transport INTEGER NOT NULL DEFAULT 0");
  }
  if (!signupCols.some((c) => c.name === "commitment")) {
    db.exec("ALTER TABLE match_signups ADD COLUMN commitment INTEGER NOT NULL DEFAULT 1");
  }

  migrateMatchLineupSlotsSlotIndexMax(db);

  db.exec(`
    CREATE TABLE IF NOT EXISTS match_transport_messages (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      match_id INTEGER NOT NULL,
      user_id INTEGER NOT NULL,
      body TEXT NOT NULL,
      created_at TEXT NOT NULL DEFAULT (datetime('now')),
      FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
      FOREIGN KEY (user_id) REFERENCES users(id)
    );
  `);
  db.exec(`
    CREATE INDEX IF NOT EXISTS idx_transport_msg_match_created
    ON match_transport_messages(match_id, created_at);
  `);
  db.exec(`
    CREATE TABLE IF NOT EXISTS match_participation_survey (
      user_id INTEGER NOT NULL,
      match_id INTEGER NOT NULL,
      played INTEGER NOT NULL,
      answered_at TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (user_id, match_id),
      FOREIGN KEY (user_id) REFERENCES users(id),
      FOREIGN KEY (match_id) REFERENCES matches(id)
    );
    CREATE INDEX IF NOT EXISTS idx_match_participation_survey_match
    ON match_participation_survey(match_id);
  `);
  db.exec(`
    CREATE TABLE IF NOT EXISTS match_attendance (
      match_id INTEGER NOT NULL,
      user_id INTEGER NOT NULL,
      present INTEGER NOT NULL,
      marked_by_admin_id INTEGER NOT NULL,
      marked_at TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (match_id, user_id),
      FOREIGN KEY (match_id) REFERENCES matches(id) ON DELETE CASCADE,
      FOREIGN KEY (user_id) REFERENCES users(id),
      FOREIGN KEY (marked_by_admin_id) REFERENCES users(id)
    );
    CREATE INDEX IF NOT EXISTS idx_match_attendance_match
    ON match_attendance(match_id);
  `);
  db.exec(`
    CREATE TABLE IF NOT EXISTS participation_survey_answer (
      user_id INTEGER NOT NULL,
      survey_key TEXT NOT NULL,
      played INTEGER NOT NULL,
      answered_at TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (user_id, survey_key),
      FOREIGN KEY (user_id) REFERENCES users(id)
    );
    CREATE TABLE IF NOT EXISTS standalone_match_stats (
      user_id INTEGER NOT NULL,
      survey_key TEXT NOT NULL,
      goals INTEGER NOT NULL DEFAULT 0,
      assists INTEGER NOT NULL DEFAULT 0,
      distance REAL NOT NULL DEFAULT 0,
      saves INTEGER NOT NULL DEFAULT 0,
      updated_at TEXT NOT NULL DEFAULT (datetime('now')),
      PRIMARY KEY (user_id, survey_key),
      FOREIGN KEY (user_id) REFERENCES users(id)
    );
  `);

  const appSettingsCols = db.prepare("PRAGMA table_info(app_settings)").all() as { name: string }[];
  if (!appSettingsCols.some((c) => c.name === "home_youtube_url")) {
    db.exec("ALTER TABLE app_settings ADD COLUMN home_youtube_url TEXT");
  }

  // Upewnij się, że istnieje pojedynczy wiersz z ustawieniami (id=1).
  const hasSettings = db.prepare("SELECT 1 AS ok FROM app_settings WHERE id = 1").get() as
    | { ok: 1 }
    | undefined;
  if (!hasSettings) {
    db.prepare("INSERT INTO app_settings (id, match_notification_prompt_enabled) VALUES (1, 0)").run();
  }
}

/**
 * Jedna instancja bazy na proces (lokalny plik lub klient Turso).
 * Na Vercelu wymagane jest `TURSO_DATABASE_URL` — lokalny plik w /tmp nie jest współdzielony między instancjami.
 */
export async function getDb(): Promise<AppDb> {
  if (isVercel() && !hasTursoEnv()) {
    throw new Error(
      "Na Vercelu ustaw TURSO_DATABASE_URL (oraz TURSO_AUTH_TOKEN z panelu Turso). Lokalny plik SQLite nie działa poprawnie na serverless."
    );
  }

  if (hasTursoEnv()) {
    if (!libsqlClient) {
      libsqlClient = createClient({
        url: process.env.TURSO_DATABASE_URL!,
        authToken: process.env.TURSO_AUTH_TOKEN?.trim() || undefined,
      });
    }
    if (!libsqlSchemaReady) {
      await withTransientNetworkRetries(
        async () => {
          await initLibsqlSchema(libsqlClient!);
        },
        {
          onBeforeRetry: () => {
            libsqlClient?.close();
            libsqlClient = createClient({
              url: process.env.TURSO_DATABASE_URL!,
              authToken: process.env.TURSO_AUTH_TOKEN?.trim() || undefined,
            });
          },
        }
      );
      libsqlSchemaReady = true;
    }
    return createLibsqlFacade(libsqlClient);
  }

  if (!sqliteInstance) {
    const p = resolveDatabaseFilePath();
    fs.mkdirSync(path.dirname(p), { recursive: true });
    sqliteInstance = new Database(p);
    sqliteInstance.pragma(isVercel() ? "journal_mode = DELETE" : "journal_mode = WAL");
    initSchemaSync(sqliteInstance);
  }
  return createSqliteFacade(sqliteInstance);
}

export async function logActivity(userId: number | null, action: string) {
  const db = await getDb();
  await db.prepare("INSERT INTO activity_log (user_id, action) VALUES (?, ?)").run(userId, action);
}

export type UserRow = {
  id: number;
  first_name: string;
  last_name: string;
  player_alias: string;
  is_admin: number;
  profile_photo_path?: string | null;
  /** Adres do powiadomień o meczach (opcjonalny). */
  email?: string | null;
  /** 1 = zgoda na e‑maile o nowych terminach. */
  match_notifications_consent?: number;
  /** 1 = użytkownik udzielił odpowiedzi w oknie powitalnym (nie pokazuj ponownie). */
  notification_prompt_completed?: number;
  /** Skrót bcrypt PIN-u; NULL = wymagane ustawienie przy pierwszym logowaniu lub po resecie. */
  pin_hash?: string | null;
  /** 1 = użytkownik zgłosił „zapomniałem PIN-u” (widoczne dla admina). */
  pin_reset_requested?: number;
  /** Wersja sesji — inkrementacja unieważnia istniejące JWT (np. reset PIN przez admina). */
  auth_version?: number;
  /** Propozycja nowego PIN-u (bcrypt); oczekuje na zatwierdzenie przez admina. */
  pin_hash_pending?: string | null;
  /** Motyw interfejsu: jasny lub ciemny. */
  ui_theme?: string | null;
};

export type MatchRow = {
  id: number;
  match_date: string;
  match_time: string;
  location: string;
  max_slots: number;
  signed_up: number;
  played: number;
  lineup_public: number;
  /** Kwota wpisowego za mecz (PLN); ustawiana przez administratora. */
  fee_pln?: number | null;
  /** 1 = mecz został anulowany. */
  cancelled?: number;
  /** Powód anulacji meczu. */
  cancellation_reason?: string | null;
};
